  ('ex_360_breathing', '360-breathing', '360 Breathing', 'mobility', '["diaphragm","pelvic_floor","intercostals"]', NULL, '["pelvic_floor","breathing","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit with hands on ribcage, thumbs at back","Inhale: feel ribs expand in all directions — front, sides, back","Exhale: ribs draw in, pelvic floor gently lifts","Do 8 slow breaths"],"cues":["Think of breathing into your whole torso","Back ribs expanding is the key sensation","Calming for third trimester breathlessness"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
