  ('ex_4_7_8_breathing', '4-7-8-breathing', '4-7-8 Breathing', 'recovery', '["diaphragm","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably, tip of tongue behind upper front teeth","Exhale completely through the mouth","Close mouth and inhale through nose for 4 counts","Hold breath for 7 counts","Exhale through mouth for 8 counts","This is one cycle — repeat 4 times"],"cues":["Powerful nervous system reset","May feel dizzy at first — reduce hold to 4-4-6","Excellent before sleep"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
