  ('ex_5_senses_grounding', '5-senses-grounding', '5 Senses Grounding', 'recovery', '["nervous_system"]', NULL, '["recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Notice 5 things you can see","4 things you can physically feel","3 things you can hear","2 things you can smell","1 thing you can taste","Take one long slow breath"],"cues":["Also called 5-4-3-2-1 grounding","Brings you back to the present moment","Very helpful for anxiety during pregnancy"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
