  ('ex_alternate_nostril', 'alternate-nostril-breathing', 'Alternate Nostril Breathing', 'recovery', '["diaphragm","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably, right hand raised to face","Close right nostril with right thumb, inhale left","Close left nostril with ring finger, release thumb, exhale right","Inhale right","Close right, release left, exhale left","That is one cycle — repeat 5–10 times"],"cues":["Balances left and right brain hemispheres","Good for anxiety and focus","Avoid retention (holding) during pregnancy"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
