  ('ex_ankle_mobility', 'ankle-mobility-circles', 'Ankle Mobility Circles', 'mobility', '["ankles","calves","tibialis_anterior"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit or stand, lift one foot off the floor","Draw large circles with your foot clockwise 10 times","Reverse 10 times","Switch feet"],"cues":["Point and flex through the full range","Helps with pregnancy swelling and circulation","Also do toe spells (trace letters with toes) for variety"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
