  ('ex_breath_counting', 'breath-counting', 'Breath Counting', 'recovery', '["diaphragm","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably, eyes closed","Breathe naturally — don''t control it","Count each exhale from 1 to 10","When you reach 10, start again from 1","If you lose count, simply begin at 1 again"],"cues":["A simple mindfulness anchor","Losing count is normal — just restart without judgment","5 minutes is plenty"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
