  ('ex_cat_cow_pregnancy', 'cat-cow-pregnancy', 'Cat-Cow (Pregnancy-Friendly)', 'mobility', '["spine","lower_back","core","pelvic_floor"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe","pelvic_floor"]', '["none"]', NULL, '{"steps":["On all fours, wrists under shoulders, knees under hips","Inhale: gently let belly drop, lift tailbone and head (Cow)","Exhale: round spine gently toward ceiling, tuck chin and tailbone (Cat)","Move slowly and deliberately, following your breath"],"cues":["Much gentler version — do not overdo the arch","On all fours is comfortable for the belly","Syncing breath with movement calms the nervous system"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
