  ('ex_exhalation_core', 'exhalation-core-engagement', 'Exhalation Core Engagement', 'mobility', '["transverse_abdominis","pelvic_floor","intercostals"]', NULL, '["pelvic_floor","breathing","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit or stand","Take a natural breath in","As you exhale slowly through pursed lips, feel your lower belly gently drawing inward","Add a light pelvic floor lift on the exhale","Repeat for 8–10 breaths"],"cues":["Exhale should be 4–6 seconds","Don''t force — let exhale do the work","The exhale IS the core exercise"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_eye_palming', 'eye-palming', 'Eye Palming', 'recovery', '["eyes","nervous_system"]', NULL, '["recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Rub palms together briskly for 10 seconds until warm","Cup warm palms gently over closed eyes — no pressure on eyeballs","Breathe slowly and let eyes completely relax in the darkness","Hold for 60–90 seconds","Repeat 2–3 times"],"cues":["Relieves eye strain and screen fatigue","The warmth and darkness are very soothing","Add a couple drops of lavender to palms for added calm"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
