  ('ex_fire_hydrant', 'fire-hydrant', 'Fire Hydrant', 'strength', '["hip_abductors","glutes","core"]', NULL, '["bodyweight","floor","low_impact","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["On all fours, wrists under shoulders","Keeping knee bent, lift right knee out to the side to hip height","Hold 1 second","Lower without touching floor","15 reps each side"],"cues":["Keep core stable","Don''t rotate the spine","Great hip mobility + strength combo"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1742860800000);
