  ('ex_forearm_wrist_stretch', 'forearm-wrist-stretch', 'Forearm & Wrist Stretch', 'mobility', '["forearms","wrists","biceps"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Extend right arm straight, palm facing up","Use left hand to gently pull fingers down toward floor","Hold 20 seconds (feels the underside of forearm)","Flip palm down, pull fingers up — hold 20 seconds","Switch arms"],"cues":["Gentle pressure only","Helps with wrist swelling in pregnancy (carpal tunnel)","Essential for new parents carrying a baby"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
