  ('ex_glute_piriformis_stretch', 'glute-piriformis-stretch', 'Glute & Piriformis Stretch', 'mobility', '["glutes","piriformis","hip_external_rotators"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on back, knees bent","Cross right ankle over left knee","Flex right foot","Either stay here or reach through to hold left thigh","Gently draw left leg toward chest","Hold 30–60 seconds, switch sides"],"cues":["Flex the top foot to protect the knee","A figure-four stretch lying down","Excellent for sciatic nerve tension"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
