  ('ex_good_morning', 'good-morning-bodyweight', 'Good Morning', 'strength', '["hamstrings","lower_back","glutes"]', NULL, '["bodyweight","no_floor","low_impact","quiet","pregnancy_safe","loads_lower_back"]', '["none"]', NULL, '{"steps":["Stand feet hip-width, hands behind head or crossed on chest","Soft bend in knees","Hinge forward from hips, pushing them back","Lower torso until parallel or hamstrings feel the stretch","Drive hips forward to return"],"cues":["Flat back throughout","Feel the hamstring stretch","Great hip hinge pattern for everyday movement"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1744900000000);
