  ('ex_grapevine', 'grapevine-step', 'Grapevine Step', 'cardio', '["legs","glutes","core"]', NULL, '["bodyweight","no_floor","low_impact","quiet","pregnancy_safe","postnatal_safe","loads_ankle"]', '["none"]', NULL, '{"steps":["Step right foot to the right","Cross left foot behind right","Step right foot to the right again","Tap left foot next to right","Reverse direction"],"cues":["Side-to-side stepping pattern","Add arm swings for intensity","Coordination + cardio combined"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1744900000000);
