  ('ex_gratitude_reflection', 'gratitude-reflection', 'Gratitude Reflection', 'recovery', '["nervous_system"]', NULL, '["recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably with eyes closed","Bring to mind 3 specific things you are grateful for today","For each one, sit with the feeling for 10–15 seconds","Notice any physical sensation of warmth or ease","Open eyes slowly"],"cues":["Specificity matters — ''my hot coffee'' not just ''coffee''","Research shows this lowers cortisol","A powerful emotional recovery tool"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
