  ('ex_half_kneeling_hip_opener', 'half-kneeling-hip-opener', 'Half Kneeling Hip Opener', 'mobility', '["hip_flexors","adductors","glutes"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet","pregnancy_safe"]', '["none"]', NULL, '{"steps":["Kneel on right knee, left foot forward in a 90° lunge","Keep right knee on floor, left knee over ankle","Shift weight forward gently until you feel the right hip flexor stretch","Add a gentle side reach for extra thoracic opening","Hold 30 seconds each side"],"cues":["Tall spine throughout","Squeeze right glute for deeper hip flexor stretch","Great for hip flexor tightness from sitting"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
