  ('ex_heel_slides', 'heel-slides', 'Heel Slides', 'mobility', '["transverse_abdominis","hip_flexors","pelvic_floor"]', NULL, '["pelvic_floor","floor","low_impact","no_sweat","quiet","supine","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on back, knees bent","Exhale and brace core gently","Slowly slide one heel along the floor until leg is nearly straight","Slide back in","Alternate legs — 8 per side"],"cues":["Keep lower back still throughout","Breathe continuously","Great early postnatal core reconnection exercise"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1742860800000);
