  ('ex_humming_breath', 'humming-bee-breath', 'Humming Bee Breath', 'recovery', '["diaphragm","vocal_cords","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably, close eyes if you wish","Inhale fully through nose","On the exhale, make a gentle humming sound (like a bee)","Feel the vibration in your lips, nose, and skull","Repeat 6–8 times"],"cues":["The humming triggers the vagus nerve","Deeply calming — great for stress and nausea","Sound can be soft — you don''t need to be loud"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
