  ('ex_kegel_elevator', 'kegel-elevator', 'Kegel Elevator', 'mobility', '["pelvic_floor"]', NULL, '["pelvic_floor","kegel","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably","Imagine your pelvic floor is an elevator","Floor 1: gentle squeeze","Floor 2: a little more","Floor 3: maximum gentle lift","Slowly descend floor by floor","Rest completely before repeating"],"cues":["No rushing — slow and deliberate","Notice each level of engagement","Great for body awareness"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1742860800000);
