  ('ex_kegel_hold', 'kegel-hold', 'Kegel Hold', 'mobility', '["pelvic_floor"]', NULL, '["pelvic_floor","kegel","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit, stand, or lie comfortably","Identify your pelvic floor muscles (the ones you use to stop urination)","Squeeze and lift them upward","Hold for 5–10 seconds","Slowly release and rest for equal time","Repeat 10 times"],"cues":["Don''t hold your breath","Keep buttocks and thighs relaxed","Quality over quantity"]}', NULL, '{"supports":["reps","sets","time"]}', NULL, 1, 1742860800000, 1742860800000);
