  ('ex_labour_breathing', 'labour-breathing-prep', 'Labour Breathing Preparation', 'recovery', '["diaphragm","pelvic_floor","nervous_system"]', NULL, '["breathing","pelvic_floor","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe"]', '["none"]', NULL, '{"steps":["Sit or kneel comfortably, or find your most comfortable position","Practice slow deep inhale through nose (4–6 counts)","Long, controlled exhale through softly open mouth (6–8 counts)","On exhale, let jaw, face, shoulders, and pelvic floor all release","Repeat for 5–10 minutes"],"cues":["This IS the most useful thing to practice in T3","Exhale is the tool — the release is everything","Practice daily from 36 weeks"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
