  ('ex_legs_up_wall', 'legs-up-wall', 'Legs Up the Wall', 'recovery', '["hamstrings","lower_back","nervous_system"]', NULL, '["recovery","floor","low_impact","no_sweat","quiet","supine","inversion","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit sideways against a wall","Swing legs up to rest against the wall as you lie back","Arms out to sides, palms up","Stay for 5–15 minutes"],"cues":["Excellent for swollen legs and feet","Mild inversion — avoid in late pregnancy (use supported side-lying instead)","One of the most restorative postures there is"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
