  ('ex_neck_shoulder_massage', 'neck-shoulder-self-massage', 'Neck & Shoulder Self-Massage', 'recovery', '["traps","neck","shoulders"]', NULL, '["recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit comfortably","Use right hand to squeeze and release left trapezius muscle (top of shoulder)","Work from the base of skull down toward the shoulder","Switch sides","Use fingertips to gently press base of skull — hold each point 10–20 seconds"],"cues":["Pressure should feel like pleasant relief","Good for feeding-posture tension in postnatal period","Can do with a warm compress first"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
