  ('ex_ocean_breath', 'ocean-breath', 'Ocean Breath (Ujjayi)', 'recovery', '["diaphragm","throat","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Breathe in through the nose","As you exhale through the nose, slightly constrict the back of the throat","This creates a soft ocean wave or Darth Vader sound","Slow, steady, 4–6 count inhale and exhale","Repeat for 2–5 minutes"],"cues":["The sound means you''re doing it right","Keeps the mind anchored to breath","Popular in yoga and prenatal classes"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
