  ('ex_standing_hip_abduction', 'standing-hip-abduction', 'Standing Hip Abduction', 'strength', '["hip_abductors","glutes"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand on one foot (hold wall for balance)","Slowly raise other leg out to the side to hip height","Hold 1 second","Lower slowly","12 reps each side"],"cues":["Keep pelvis level","Foot stays flexed","Excellent for pelvic stability during pregnancy"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1742860800000);
