  ('ex_standing_pelvic_rock', 'standing-pelvic-rock', 'Standing Pelvic Rock', 'mobility', '["lower_back","pelvic_floor","core"]', NULL, '["pelvic_floor","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand feet hip-width, knees slightly bent, hands on hips","Gently rock pelvis forward (arch lower back slightly)","Then rock pelvis backward (flatten lower back)","Find a slow, rhythmic motion","Repeat for 30 to 60 seconds"],"cues":["Think of a gentle rocking motion","Good for lower back tension in pregnancy","Also used during labour for pain relief"]}', NULL, '{"supports":["time","reps"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_standing_side_stretch', 'standing-side-stretch', 'Standing Side Stretch', 'mobility', '["obliques","lats","intercostals"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand with feet hip-width","Reach right arm overhead and lean gently to the left","Feel the stretch along your right side from hip to fingertips","Hold 20 seconds, switch sides"],"cues":["Don''t rotate — pure side bend","Keep feet grounded","Feels wonderful as pregnancy belly grows"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_standing_twist_march', 'standing-twist-march', 'Standing Twist March', 'cardio', '["obliques","hip_flexors","core"]', NULL, '["bodyweight","no_floor","low_impact","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand with hands behind head","March in place, lifting knees high","As right knee comes up, rotate left shoulder gently toward it","Alternate, keeping rhythm moderate"],"cues":["Don''t crunch — rotate and march","Maintain tall posture","Excellent warm-up movement"]}', NULL, '{"supports":["time","reps"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_sumo_squat', 'sumo-squat', 'Sumo Squat', 'strength', '["adductors","glutes","quadriceps"]', NULL, '["bodyweight","no_floor","low_impact","quiet","pregnancy_safe","postnatal_safe","loads_knee"]', '["none"]', NULL, '{"steps":["Stand with feet wider than shoulder-width, toes turned out 45°","Lower hips straight down, keeping knees tracking toes","Pause at bottom","Drive through heels to stand"],"cues":["Chest stays tall","Great inner thigh target","Very pregnancy-friendly — room for belly"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_supported_glute_bridge', 'supported-glute-bridge', 'Supported Glute Bridge', 'mobility', '["glutes","hamstrings","pelvic_floor","transverse_abdominis"]', NULL, '["pelvic_floor","floor","low_impact","no_sweat","quiet","supine","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on back, knees bent, feet flat, hip-width","Exhale: engage pelvic floor and core","Press through heels to lift hips to a straight line from knees to shoulders","Hold 2 seconds at the top","Lower slowly through your spine"],"cues":["Don''t overextend the back","Squeeze glutes at top","Great postnatal posterior chain activation"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_supported_side_rest', 'supported-side-lying-rest', 'Supported Side-Lying Rest', 'recovery', '["nervous_system","full_body"]', NULL, '["recovery","floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on your left side (preferred in pregnancy for circulation)","Place a pillow between your knees","Rest head on a pillow","Allow everything to soften","Stay 5–15 minutes"],"cues":["The pregnancy-safe savasana","Left side improves blood flow to the uterus","Great between contractions in labour too"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_supported_wall_squat', 'supported-wall-squat', 'Supported Wall Squat', 'mobility', '["quadriceps","glutes","hip_flexors","inner_thighs"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe","loads_knee"]', '["none"]', NULL, '{"steps":["Stand with back against wall, feet hip-width, about 30cm from wall","Slide down the wall into a seated position (thighs parallel or above parallel)","Hold position — breathe naturally","Slide back up"],"cues":["Also called ''wall squat''","Comfortable supported position for third trimester","Add a block under your heels if calves are tight"]}', NULL, '{"supports":["time","sets"]}', NULL, 1, 1742860800000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_tension_release_viz', 'tension-release-visualization', 'Tension Release', 'recovery', '["nervous_system","muscles"]', NULL, '["recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit or lie comfortably","Take a slow breath in and imagine collecting all your tension","As you exhale slowly, imagine the tension leaving your body as mist","Repeat 5–8 times with intention","Notice your body softening with each exhale"],"cues":["Simple and powerful","Works in any position — great for mid-night wakeups","Combine with progressive muscle relaxation"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_thoracic_ext_chair', 'thoracic-extension-chair', 'Thoracic Extension on Chair', 'mobility', '["thoracic_spine","chest","shoulders"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["chair"]', NULL, '{"steps":["Sit upright in a sturdy chair","Clasp hands behind head, elbows wide","Gently arch back over the top edge of the chair back","Hold 3–5 seconds, return upright","Repeat 5–8 times, moving slightly up and down the spine"],"cues":["Supported thoracic extension — very gentle","Great for desk workers and pregnancy posture","Don''t force — just let gravity help"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_tuck_jump', 'tuck-jump', 'Tuck Jump', 'cardio', '["quadriceps","calves","core"]', NULL, '["bodyweight","no_floor","high_impact","loud","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand with feet hip-width","Jump and drive both knees toward chest at the peak","Land softly with knees bent","Immediate next rep"],"cues":["Maximum effort jump","Very high impact — not for pregnancy or early postnatal","Great for athletic conditioning"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1742860800000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_wall_chest_stretch', 'wall-chest-stretch', 'Wall Chest Stretch', 'mobility', '["chest","anterior_deltoids","biceps"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand sideways to wall","Place right palm flat on wall, arm straight","Gently rotate body left until you feel the chest stretch","Hold 20–30 seconds","Switch sides"],"cues":["Keep arm at shoulder height","Very gentle rotation","Great for breastfeeding posture recovery"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_wide_step_touch', 'wide-step-touch', 'Wide Step Touch', 'cardio', '["legs","glutes","core"]', NULL, '["bodyweight","no_floor","low_impact","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand tall","Step right foot wide to the right","Bring left foot to meet it, touching down briefly","Step left wide to the left","Bring right foot to meet","Add arm raises for intensity"],"cues":["Wider steps = more glute engagement","Keep chest up","Great continuous warm-up movement"]}', NULL, '{"supports":["time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_worlds_greatest_stretch', 'world-greatest-stretch', 'World''s Greatest Stretch', 'mobility', '["hip_flexors","thoracic_spine","hamstrings","glutes"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["From push-up position, step right foot outside right hand","Drop left knee to floor","Rotate right arm toward ceiling, opening chest","Hold 2 seconds, return hand to floor","Repeat on other side — 5 per side"],"cues":["Slow and deliberate","Brilliant full-body mobility sequence","Modify: both knees on floor in lunge position"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_yawn_sigh', 'yawn-sigh-breath', 'Yawn & Sigh Breath', 'recovery', '["diaphragm","jaw","nervous_system"]', NULL, '["breathing","recovery","no_floor","low_impact","no_sweat","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Take a big exaggerated yawn — open mouth as wide as possible, inhale fully","At the top, hold for a moment","Release with a long audible sigh — ahhh or haaa","Let the face and shoulders completely drop on the sigh","Repeat 5 times"],"cues":["Yes, fake yawns often trigger real ones","One of the fastest ways to release jaw and neck tension","Excellent for anxiety and labour preparation"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1742860800000, 1742860800000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_cycling_intervals_indoor', 'cycling-intervals-indoor', 'Cycling Intervals (Indoor)', 'cardio', '["quads","hamstrings","glutes","cardiovascular_system"]', NULL, '["cardio","low_impact","quiet","indoor","high_intensity","hiit"]', '["indoor_bike","exercise_bike"]', NULL, '{"steps":["Warm up at 70–90W for 5 minutes at 80 RPM — HR should reach 110–120 bpm before the intervals begin.","Effort interval: increase resistance to your maximum sustainable output. Target 150–250W at 90–110 RPM. This should feel like 8–9 out of 10 effort — HR target 160–175 bpm.","Recovery interval: drop to 60–90W at 70–80 RPM. Let HR fall back to 120–130 bpm before the next effort begins. Full recovery makes HIIT effective.","Repeat the effort/recovery pattern. Final 5 minutes: cool down at 60–80W, 75 RPM."],"cues":["💡 Watt targets: beginners 120–160W effort / 60–80W recovery. Intermediate 160–220W / 70–90W. Advanced 200–280W+ / 80–100W.","💡 RPM during efforts: 90–110 revolutions per minute. High cadence maximises cardiovascular stimulus.","💡 HIIT on a bike is joint-friendly — you can push harder than running intervals with lower injury risk","💡 HR 165–175 bpm during effort is the target. If you cannot reach 160 bpm, increase resistance."]}', NULL, '{"supports":["time"],"base_duration_sec":1080}', '{"substitutions":["steady-indoor-cycle","stationary-bike-steady"]}', 1, 1743897600000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_easy_run_outdoor', 'easy-run-outdoor', 'Easy Run (Outdoor)', 'cardio', '["quads","hamstrings","calves","glutes","cardiovascular_system"]', NULL, '["cardio","high_impact","outdoor","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Set treadmill to 1% incline — this compensates for the absence of air resistance and more closely matches outdoor running.","Start at 7.5 km/h and adjust until your heart rate settles at 125–135 bpm. This is Zone 2 — your aerobic base pace.","Target speed range: 7–9 km/h (6:40–8:30 min/km equivalent). Your exact Zone 2 speed depends on fitness — let HR be your only guide.","If HR exceeds 135 bpm, reduce speed by 0.3–0.5 km/h and hold there. This is not failure — it is precise Zone 2 training."],"cues":["💡 Talk test: say a full sentence without gasping. If you cannot, you have left Zone 2 — slow down","💡 1% incline is not a hill — it corrects for treadmill mechanics. Always use it for Zone 2 runs.","💡 Zone 2 on a treadmill: 7.5–8.5 km/h is the reference range for moderate-fitness runners","💡 Zone 2 builds your aerobic engine. Slower than it feels right is usually correct on easy days."]}', NULL, '{"supports":["time"],"base_duration_sec":1500}', '{"substitutions":["tempo-run-outdoor","run-intervals-outdoor","treadmill-run-steady"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_rowing_intervals', 'rowing-intervals', 'Rowing Intervals', 'cardio', '["legs","back","shoulders","arms","core","cardiovascular_system"]', NULL, '["cardio","strength","low_impact","indoor","full_body","high_intensity","hiit","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Warm up with 3–5 minutes at easy pace: 24–26 SPM, split around 2:35–2:45 /500m, HR below 130.","Effort interval: drive hard for the prescribed duration. Target split: under 2:10 /500m at 24–28 SPM. This is near-maximum effort — HR target 165–175 bpm.","Recovery interval: drop to 18–20 SPM at 2:40–2:50 /500m. Let HR fall below 130 before the next effort. Active recovery — keep rowing, do not stop.","Repeat the effort/recovery pattern throughout the session."],"cues":["💡 HIIT rowing split targets: beginners under 2:20 /500m, intermediate under 2:10, advanced under 2:00","💡 SPM during efforts: 24–28 strokes per minute. Increase power, not SPM, to hit your split target","💡 The catch is where power begins: arms straight, shins vertical, weight forward — then legs drive","💡 Rowing HIIT is among the highest caloric-burn HIIT modalities — 800–1000 kcal/hr at max effort"]}', NULL, '{"supports":["time"],"base_duration_sec":1080}', '{"substitutions":["rowing-steady-state"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_rowing_steady', 'rowing-steady-state', 'Rowing — Steady State', 'cardio', '["legs","back","shoulders","arms","core"]', NULL, '["cardio","strength","low_impact","indoor","full_body","zone2","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Set resistance so you maintain 18–20 strokes per minute (SPM) at a comfortable, sustained effort.","Target split: 2:20–2:40 per 500m. This is Zone 2 rowing — HR should settle at 125–135 bpm within 5 minutes.","Hold this pace for the full session. If HR rises above 135, reduce stroke rate by 1–2 SPM or reduce drive power.","Focus on the catch-drive-finish-recovery sequence: legs first, then lean back, then arms draw to the lower chest."],"cues":["💡 Talk test applies on the rowing machine too — full sentences should be possible at Zone 2 effort","💡 Split target: 2:25–2:35 /500m is the standard Zone 2 reference for recreational rowers","💡 18–20 SPM: lower stroke rate forces longer, more powerful strokes — this builds aerobic efficiency","💡 Zone 2 rowing is full-body aerobic work: legs (60%), core (20%), arms (20%) at every stroke"]}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["rowing-intervals","steady-indoor-cycle"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_run_intervals_outdoor', 'run-intervals-outdoor', 'Running Intervals (Outdoor)', 'cardio', '["quads","hamstrings","calves","glutes","cardiovascular_system"]', NULL, '["cardio","high_impact","outdoor","high_intensity","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Warm-up: 5-minute easy jog","Hard effort: run fast for 60 seconds — controlled but challenging","Recovery: 90 seconds walk or very easy jog","Repeat for the session","Cool-down: 3-minute easy walk"],"cues":["Hard effort = you could not have a conversation","Recovery must be genuinely easy — it prepares the next rep","Focus on keeping form during hard effort: tall, relaxed, quick feet","💡 Beginner: 5 rounds · hard pace 5:30–6:30 min/km","💡 Intermediate: 8 rounds · hard pace 4:30–5:00 min/km","💡 Advanced: 10–12 rounds · hard pace 3:45–4:15 min/km"]}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["easy-run-outdoor","tempo-run-outdoor","treadmill-run-steady"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_stationary_bike_steady', 'stationary-bike-steady', 'Stationary Bike — Steady Ride', 'cardio', '["quads","hamstrings","glutes","calves"]', NULL, '["cardio","low_impact","quiet","indoor"]', '["exercise_bike","indoor_bike"]', NULL, '{"steps":["Adjust seat height so your knee is almost straight at the bottom of the pedal stroke","Start at low resistance and spin for 3–4 minutes to warm up","Increase resistance to your target level and find a steady rhythm","Maintain a cadence of 70–90 rpm","Every 5 minutes, check your effort — increase resistance slightly if it feels too easy","Last 3 minutes: reduce resistance and cool down"],"cues":["Sit tall — don''t hunch over the handlebars","Engage your core lightly throughout","Focus on smooth, even pressure through both legs","💡 Beginner: light–moderate resistance · RPE 4–5 · ~30 min","💡 Intermediate: moderate resistance · RPE 6 · ~40 min","💡 Advanced: moderate–heavy resistance · RPE 7 · ~50 min"],"pregnancy_note":"Stay at conversational effort (RPE ≤ 5). Upright bikes are usually more comfortable than recumbent in late pregnancy."}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["steady-indoor-cycle","cycling-intervals-indoor"]}', 1, 1743897600000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_steady_indoor_cycle', 'steady-indoor-cycle', 'Steady Indoor Cycling', 'cardio', '["quads","hamstrings","glutes","calves"]', NULL, '["cardio","low_impact","quiet","indoor"]', '["indoor_bike"]', NULL, '{"steps":["Set your bike up — saddle height so your knee has a slight bend at the bottom of the pedal stroke","Start with 5 minutes easy spinning at 80–90 rpm to warm up","Settle into your target power or perceived effort and hold it steadily","Check in every 5 minutes — adjust resistance if drifting","Keep cadence above 80 rpm throughout","Final 3–5 minutes: drop resistance and spin easy to cool down"],"cues":["Smooth circles — push forward over the top, pull back at the bottom","Relax your grip and shoulders — your legs do the work","Breathe rhythmically — match breath to pedal stroke","💡 Beginner: 70–100 W · 80–90 rpm · RPE 4–5","💡 Intermediate: 120–155 W · 85–95 rpm · RPE 6","💡 Advanced: 170–230 W · 90–100 rpm · RPE 7"],"pregnancy_note":"Keep effort conversational (RPE ≤ 5). Stop if you feel dizzy, short of breath, or any pelvic pressure."}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["stationary-bike-steady","cycling-intervals-indoor"]}', 1, 1743897600000, 1743897600000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_tempo_run_outdoor', 'tempo-run-outdoor', 'Tempo Run (Outdoor)', 'cardio', '["quads","hamstrings","calves","glutes","cardiovascular_system"]', NULL, '["cardio","high_impact","outdoor","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Walk or easy jog 5 minutes to warm up","Build to tempo pace — comfortably hard, not all-out","Maintain this pace for the bulk of the run","The two-word test: you can say two words but not a full sentence","Keep form: tall posture, slight forward lean, quick light steps","5-minute easy jog or walk cool-down at the end"],"cues":["Tempo = about 80% of max heart rate","If you can chat comfortably, go faster. If gasping, back off.","Think: controlled discomfort — not survival mode","💡 Beginner: 6:00–7:00 min/km · ~25 min (including warm-up/cool-down)","💡 Intermediate: 5:00–5:45 min/km · ~30 min total","💡 Advanced: 4:00–4:45 min/km · ~35 min total"]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["easy-run-outdoor","run-intervals-outdoor","treadmill-run-steady"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_treadmill_run_steady', 'treadmill-run-steady', 'Treadmill Run — Steady Pace', 'cardio', '["quads","hamstrings","calves","glutes","cardiovascular_system"]', NULL, '["cardio","high_impact","indoor","loads_knee","loads_ankle"]', '["treadmill"]', NULL, '{"steps":["Set incline to 1% — this better replicates outdoor running (compensates for no wind resistance)","Start at a slow walk for 2 minutes, then gradually increase speed","Find your target speed and lock it in","Keep your gaze forward and slightly down — not at your feet","Avoid holding the handrails unless needed for safety","Last 2–3 minutes: reduce speed to a walking cool-down"],"cues":["1% incline is the sweet spot for most runners","Don''t overstride — feet should land under your hips","Shorter, quicker steps are more efficient than long bounds","💡 Beginner: 7.5–8.5 km/h · 1% incline · ~20 min","💡 Intermediate: 9.5–11.0 km/h · 1% incline · ~25 min","💡 Advanced: 12.0–14.5 km/h · 1–2% incline · ~30 min"]}', NULL, '{"supports":["time"],"base_duration_sec":1500}', '{"substitutions":["easy-run-outdoor","tempo-run-outdoor"]}', 1, 1743897600000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_068', '478-breathing', '4-7-8 Breathing', 'recovery', '["diaphragm","nervous_system"]', NULL, '["recovery","breathing","quiet","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit or lie comfortably. Exhale completely through your mouth.","Inhale quietly through your nose for 4 counts.","Hold your breath for 7 counts. Then exhale completely through your mouth for 8 counts. That is one cycle. Repeat 4 times."],"cues":["💡 The extended exhale activates the parasympathetic nervous system — instant calm.","If 7 counts feels too long, scale the ratio: 2-3.5-4, keeping the 1:2 exhale ratio."]}', NULL, '{"supports":["time"],"base_duration_sec":180}', '{"substitutions":["box-breathing","alternate-nostril-breathing","pursed-lip-breathing"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_049', 'active-thoracic-rotation', 'Active Thoracic Rotation', 'mobility', '["thoracic_spine","obliques","rotator_cuff"]', NULL, '["mobility","low_impact","floor","pregnancy_safe"]', '["none"]', NULL, '{"steps":["Lie on your side in a foetal position, knees stacked and bent to 90°, arms extended in front.","Keeping your knees together and lower body still, rotate your top arm open toward the ceiling and behind you.","Follow your hand with your eyes. Return and repeat. Switch sides after reps."],"cues":["💡 Breathe out as you open — the exhale relaxes the chest and allows more rotation.","The lower body stays completely still — all movement comes from the thoracic spine."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["seated-thoracic-rotation","cat-cow-flow","seated-spinal-twist"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_073', 'alternating-front-kick', 'Alternating Front Kick', 'cardio', '["hip_flexors","quads","glutes","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","dynamic","no_floor","balance"]', '["none"]', NULL, '{"steps":["Stand tall, feet hip-width. Shift weight to your left leg.","Kick your right leg forward to hip height (or comfortable height), keeping it reasonably straight. Then lower and switch.","Increase tempo once you have the balance — swing your opposite arm with each kick."],"cues":["💡 Control the lowering phase — don''t let the leg drop back.","Look straight ahead, not down — balance improves immediately."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["high-knees","lateral-knee-raise","standing-bicycle"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_019', 'band-bicep-curl', 'Resistance Band Bicep Curl', 'strength', '["biceps_brachii","brachialis"]', NULL, '["strength","pull","low_impact","no_floor"]', '["resistance_bands"]', NULL, '{"steps":["Stand on the center of the band with feet hip-width. Hold one end in each hand with an underhand grip, arms extended at your sides.","Curl both hands toward your shoulders, keeping your elbows pinned to your sides. Maintain steady tension throughout the movement.","Lower slowly — the resistance stays on all the way down, unlike with free weights."],"cues":["💡 Band resistance peaks at full extension and is minimal at the start — the opposite of a dumbbell. Great for end-range bicep strength.","Keep your elbows locked in place. If they drift forward, the work shifts away from the bicep."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-bicep-curl","dumbbell-concentration-curl","dumbbell-hammer-curl"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_018', 'band-face-pull', 'Resistance Band Face Pull', 'strength', '["rear_deltoid","rotator_cuff","rhomboids","mid_traps"]', NULL, '["strength","pull","low_impact","no_floor","shoulder_health","loads_shoulder"]', '["resistance_bands"]', NULL, '{"steps":["Anchor the band at face height. Hold one end in each hand with an overhand grip, arms extended forward.","Pull the band toward your face, driving your elbows wide and high. Your hands should finish level with your ears, elbows above shoulder height.","Return to start with control. Resist the band pulling your hands back together."],"cues":["💡 Face pulls are the antidote to too much pressing — they balance the shoulder and develop the rear deltoid that most people neglect.","Elbows high and wide is the essential cue. If your elbows drop, you are doing a row, not a face pull."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["band-pull-apart","dumbbell-rear-delt-fly"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_023', 'band-hip-abduction-standing', 'Band Standing Hip Abduction', 'strength', '["glute_medius","hip_abductors","tensor_fasciae_latae"]', NULL, '["strength","low_impact","glutes","no_floor"]', '["resistance_bands"]', NULL, '{"steps":["Anchor the band at ankle height. Loop the other end around one ankle. Stand with the anchor to your side or in front, holding a wall for balance if needed.","Lift your outside leg out to the side against the band, keeping it straight. Your hip drives the movement — not your lower back.","Lower slowly — resist the band pulling your leg in. Complete all reps, then switch sides."],"cues":["💡 This targets the gluteus medius — the hip stabiliser critical for knee alignment when running, landing, and squatting.","Do not tilt your torso as you lift. If you lean, the load has moved from your hip to your back."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["side-lying-hip-abduction","standing-hip-abduction","band-lateral-walk"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_020', 'band-lateral-walk', 'Resistance Band Lateral Walk', 'strength', '["glute_medius","hip_abductors","quads"]', NULL, '["strength","low_impact","glutes","no_floor","loads_ankle"]', '["resistance_bands"]', NULL, '{"steps":["Place the band just above your knees. Stand in a half-squat position with feet hip-width — there should be constant tension in the band.","Step to the right with your right foot, then bring your left foot in to maintain the hip-width stance. Do not let feet come together.","Walk the prescribed steps in one direction, maintaining the squat depth throughout, then reverse."],"cues":["💡 Staying in the squat is the exercise — the moment you stand up, the glute work stops completely.","Feel the hip abductor activate as you step out. That is the gluteus medius — a muscle critical for knee and hip stability."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["standing-hip-abduction","side-lying-hip-abduction","band-hip-abduction-standing"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_021', 'band-overhead-press', 'Resistance Band Overhead Press', 'strength', '["anterior_deltoid","medial_deltoid","triceps","upper_traps"]', NULL, '["strength","push","low_impact","no_floor","loads_shoulder"]', '["resistance_bands"]', NULL, '{"steps":["Stand on the center of the band with feet shoulder-width. Hold the ends at shoulder height, elbows forward. Create tension in the band before starting.","Press overhead until arms are fully extended. Core braced — do not let your lower back arch as the arms rise.","Lower slowly back to shoulder height, controlling the band the entire way down."],"cues":["💡 The band gets harder as it stretches — the top of the press is the most demanding portion, unlike free weights.","Keep your ribs down throughout. Overhead pressing quickly exposes any lower back weakness."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-shoulder-press","dumbbell-seated-overhead-press","dumbbell-arnold-press"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_017', 'band-pull-apart', 'Resistance Band Pull-Apart', 'strength', '["rear_deltoid","rhomboids","lower_traps"]', NULL, '["strength","pull","low_impact","no_floor","shoulder_health","loads_shoulder"]', '["resistance_bands"]', NULL, '{"steps":["Hold the band with both hands shoulder-width apart in front of you at shoulder height, arms straight.","Pull the band apart by moving your arms out to the sides until it touches your chest.","Return slowly — resist the band pulling your hands back together."],"cues":["💡 Ideal as a warm-up or between push sets to balance the shoulder.","Keep the movement controlled — a floppy band means no tension."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["band-face-pull","dumbbell-rear-delt-fly"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_016', 'band-row-seated', 'Resistance Band Seated Row', 'strength', '["lats","rhomboids","rear_deltoid","biceps"]', NULL, '["strength","pull","low_impact","no_floor"]', '["resistance_bands"]', NULL, '{"steps":["Sit on the floor with legs extended. Loop the band around your feet or a fixed anchor. Hold both ends with arms extended, back tall.","Row your elbows back behind you, squeezing your shoulder blades together. Bring your hands to your lower ribcage.","Return with control — resist the band pulling you forward. Do not round your back on the way out."],"cues":["💡 Sit tall the entire time — a rounded spine shifts the load to your lower back instead of your lats.","Pause for a full second at peak contraction before releasing. That pause is where the muscle gets built."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-arm-row","dumbbell-bent-over-row","band-face-pull"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_022', 'band-squat', 'Resistance Band Squat', 'strength', '["quads","glutes","hamstrings"]', NULL, '["strength","low_impact","no_floor","loads_knee"]', '["resistance_bands"]', NULL, '{"steps":["Stand on the center of the band with feet shoulder-width. Hold the ends at shoulder height or crossed over your chest.","Squat down — hips back and down, chest tall, knees tracking over toes. Go to at least parallel depth.","Drive through your heels to stand, feeling the band resistance increase as you approach the top. Squeeze glutes at lockout."],"cues":["💡 Band squats load the top of the movement differently from free weights — this trains lockout strength and hip extension power.","Use the tension at the top as a cue to push your knees out. The band mimics the feedback of a barbell perfectly."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["sumo-squat","dumbbell-goblet-squat","wall-sit"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_037', 'bear-crawl', 'Bear Crawl', 'strength', '["core","shoulders","quads","hip_flexors"]', NULL, '["strength","core","cardio","low_impact","floor","loads_shoulder"]', '["none"]', NULL, '{"steps":["Start on all fours — hands under shoulders, knees under hips. Hover knees 2–3 cm off the floor.","Move forward by stepping right hand + left knee simultaneously, then left hand + right knee.","Keep your back flat and hips level — the hover forces your core to stabilize."],"cues":["💡 Slow and controlled beats fast and sloppy — quality movement is the goal.","Reverse crawl (backward) is equally effective and challenges coordination."]}', NULL, '{"supports":["time"],"base_duration_sec":40}', '{"substitutions":["plank-shoulder-tap","mountain-climber","hollow-body-hold"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_080', 'boxing-combination', 'Boxing Combination', 'cardio', '["shoulders","triceps","core","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","upper_body","dynamic","no_floor","loads_shoulder"]', '["none"]', NULL, '{"steps":["Stand in a fighting stance: left foot slightly forward, knees soft, hands up protecting your face.","Throw a jab-cross-hook-uppercut combination: jab (left straight), cross (right straight), hook (left), uppercut (right).","Reset and repeat. Rotate your hips and pivot your feet with each power punch."],"cues":["💡 Power comes from hip rotation, not arm strength — think of the punch starting at your feet.","Light on your feet between combinations — stay in your athletic stance."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["shadow-boxing","speed-bag-simulation","seated-cardio-punch"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_087', 'brisk-walk', 'Brisk Walking', 'cardio', '["cardiovascular_system","quads","hamstrings","calves","glutes"]', NULL, '["cardio","low_impact","zone2","conditioning","outdoor","loads_knee","loads_ankle"]', '["running_shoes","treadmill"]', NULL, '{"steps":["Walk at a pace that noticeably elevates your heart rate but still allows full conversation.","Swing your arms purposefully and stride forward — not a stroll, a deliberate power walk.","Maintain this effort for the full duration without stopping."],"cues":["💡 Brisk walking at Zone 2 intensity provides cardiovascular benefit with minimal joint impact.","Ideal starting point for beginners, or as active recovery for trained athletes."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["zone2-easy-run","easy-run-outdoor"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_071', 'broad-jump', 'Broad Jump', 'cardio', '["quads","glutes","calves","hamstrings"]', NULL, '["cardio","high_impact","bodyweight","power","dynamic","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand with feet shoulder-width, knees bent in an athletic stance.","Swing your arms back and explosively drive them forward as you jump as far as possible horizontally.","Land softly with bent knees, absorbing the impact through your legs."],"cues":["💡 The arm swing generates 20–30% of the jump distance — don''t skip it.","Stick your landing for a second to build deceleration strength."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["jump-squat","tuck-jump","power-step-up-jump"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_048', 'calf-stretch-wall', 'Calf Stretch (Wall)', 'mobility', '["gastrocnemius","soleus","achilles_tendon"]', NULL, '["mobility","low_impact","no_floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Stand facing a wall, arms extended, hands flat on the wall at chest height. Step one foot back about 60-90 cm, keeping it pointing straight forward and the heel flat on the floor.","Lean gently into the wall by bending your front knee, keeping the rear knee straight and the rear heel grounded. Feel the stretch in the calf of the rear leg (gastrocnemius stretch).","After 20-30 seconds, slightly bend the rear knee — keeping the heel down. This shifts the stretch deeper into the lower calf (soleus). Hold another 20 seconds.","Switch legs and repeat."],"cues":["Both versions matter: straight knee targets the gastrocnemius (upper calf), bent knee targets the soleus (lower calf). Neither replaces the other.","Heel stays down throughout — if it rises, step closer to the wall.","💡 Tight calves are a major contributor to plantar fasciitis, Achilles issues, and knee pain. This stretch is worth doing daily, especially for runners."]}', NULL, '{"supports":["time"],"base_duration_sec":45}', '{"substitutions":["ankle-mobility-circles","single-leg-calf-raise","ankle-pumps"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_044', 'cat-cow-flow', 'Cat-Cow Spinal Flow', 'mobility', '["erector_spinae","core","spine"]', NULL, '["mobility","low_impact","floor","pregnancy_safe","postnatal_safe","breathing"]', '["none"]', NULL, '{"steps":["On all fours, wrists under shoulders, knees under hips. Neutral spine to start.","Inhale: let your belly drop toward the floor, gently lifting your tailbone and chin (cow).","Exhale: round your spine toward the ceiling, tucking your chin and tailbone (cat). Repeat slowly."],"cues":["💡 Move with your breath — inhale for cow, exhale for cat.","Move one vertebra at a time — wave through the spine rather than hinging at one spot."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["seated-thoracic-rotation","active-thoracic-rotation","cat-cow-pregnancy"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_031', 'chin-up', 'Chin-Up', 'strength', '["biceps_brachii","lats","core"]', NULL, '["strength","pull","low_impact","no_floor","loads_shoulder"]', '["pull_up_bar"]', NULL, '{"steps":["Hang from the bar with a supinated grip (palms toward you), hands roughly shoulder-width.","Pull your body up until your chin clears the bar, elbows driving down toward your hips.","Lower with control to a full dead hang."],"cues":["💡 Supinated grip recruits the biceps more — generally easier than pull-ups for beginners.","Same rules as pull-ups: full extension at the bottom, every rep."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["pull-up","inverted-row-table","dumbbell-single-arm-row"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_043', 'couch-stretch', 'Couch Stretch', 'mobility', '["hip_flexors","quads","psoas"]', NULL, '["mobility","low_impact","floor"]', '["none"]', NULL, '{"steps":["Kneel with your back to a wall or sofa. Slide your rear foot up the wall so the top of your foot and shin are resting against it — this stretches the hip flexor of that rear leg.","Bring your front foot forward and plant it flat on the floor so your front knee is directly over your ankle, thigh roughly parallel to the floor.","Squeeze the glute of the rear leg firmly and tuck your pelvis slightly. This activates the stretch — without the glute squeeze you will just feel it in your knee, not your hip flexor.","Hold for 60-90 seconds, breathing steadily. Switch sides."],"cues":["Squeezing the glute of the rear leg is not optional — it is what moves the stretch from the knee to the hip flexor where it belongs.","Upright torso throughout — if you are leaning forward, bring your front foot further out.","💡 💡 One of the most effective hip flexor stretches available — essential for runners, cyclists, and anyone who sits. 60-90 seconds per side minimum to see results."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["hip-flexor-stretch","half-kneeling-hip-opener","ninety-ninety-hip-switch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_072', 'cross-country-ski-step', 'Cross-Country Ski Step', 'cardio', '["hip_flexors","glutes","shoulders","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","dynamic","no_floor"]', '["none"]', NULL, '{"steps":["Stand with feet staggered, one foot forward, one back. Arms opposite to feet (right arm forward if left foot is forward).","Simultaneously switch your feet and arms in a scissoring motion — like cross-country skiing.","Keep the movement smooth and rhythmic, driving your arms for momentum."],"cues":["💡 Low-impact version of a sprint in terms of cardiovascular demand.","Keep the step width small and quick — bigger steps are harder to sustain."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["grapevine-step","shuffle-tap","lateral-shuffle-drill"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_090', 'cycling-hill-climb', 'Cycling Hill Climb Effort', 'cardio', '["quads","glutes","hamstrings","calves","core","cardiovascular_system"]', NULL, '["cardio","strength","low_impact","conditioning","indoor"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["Increase resistance to simulate a 6–10% gradient. Reduce cadence to 60–75 rpm.","Push through the pedals with power — heavier resistance, seated. You can also alternate seated and standing.","Climb for 5–10 minutes, then reduce resistance to spin easy for 3 minutes. Repeat."],"cues":["💡 Climbing builds power and muscular endurance simultaneously.","On a road bike outdoors, pick a real hill and ride tempo effort to the top."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["cycling-tempo-effort","cycling-zone2-ride","cycling-sweet-spot"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_099', 'cycling-outdoor-easy', 'Easy Outdoor Ride', 'cardio', '["quads","hamstrings","glutes","calves","cardiovascular_system"]', NULL, '["cardio","low_impact","zone2","conditioning","outdoor"]', '["road_bike","mountain_bike"]', NULL, '{"steps":["Set off at an easy, conversational effort — about Zone 2. Pick a flat or gently rolling route.","Maintain 80–90 rpm cadence in a gear that feels manageable but not too easy.","Cool down with a 5-minute very easy spin before stopping."],"cues":["💡 For outdoor cycling, traffic-safe awareness is a skill — plan a safe route in advance.","Shift gears to maintain cadence, not to increase resistance."]}', NULL, '{"supports":["time"],"base_duration_sec":3600}', '{"substitutions":["cycling-zone2-ride","cycling-tempo-effort","brisk-walk"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_093', 'cycling-pyramid-effort', 'Cycling Pyramid Intervals', 'cardio', '["quads","glutes","cardiovascular_system"]', NULL, '["cardio","high_intensity","hiit","low_impact","conditioning","indoor"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["After a 5-minute warm-up, build intervals in a pyramid: 1 min hard / 1 min easy, 2 min hard / 2 min easy, 3 min hard / 3 min easy, then back down: 2 min hard / 2 min easy, 1 min hard.","Hard intervals at 90–95% effort. Easy intervals genuinely easy.","Cool down 5 minutes easy."],"cues":["💡 The pyramid structure ensures variety in duration and intensity within a single session.","Mark your effort at each pyramid step and try to sustain the same perceived effort throughout."]}', NULL, '{"supports":["time"],"base_duration_sec":1980}', '{"substitutions":["cycling-sprint-intervals","cycling-sweet-spot","cycling-intervals-indoor"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_091', 'cycling-sprint-intervals', 'Cycling Sprint Intervals', 'cardio', '["quads","glutes","hamstrings","cardiovascular_system"]', NULL, '["cardio","high_intensity","hiit","low_impact","conditioning","indoor"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["Warm up 5–8 minutes easy spinning. Reach 90+ rpm cadence.","Sprint all-out for 10–20 seconds — maximum effort, maximum cadence.","Recover easy spinning for 90–120 seconds. Repeat 6–10 times."],"cues":["💡 Short sprints train peak power output — the effort must be maximal or the adaptation is lost.","Stand on the pedals for the sprint if on a stationary setup; remain seated on a smart trainer."]}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["cycling-intervals-indoor","cycling-pyramid-effort","cycling-tempo-effort"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_092', 'cycling-sweet-spot', 'Cycling Sweet Spot Training', 'cardio', '["quads","hamstrings","glutes","cardiovascular_system"]', NULL, '["cardio","low_impact","conditioning","indoor"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["Target 88–93% of FTP (or perceived effort: 7–7.5 out of 10). Harder than tempo, easier than VO2 max.","Hold this ''sweet spot'' effort in blocks of 10–20 minutes with 5 minutes easy between blocks.","Cadence: 85–95 rpm. Finish with 5 minutes easy cool-down."],"cues":["💡 Sweet spot gives 80% of the adaptation of full threshold riding for 60% of the recovery cost.","Breathing is laboured but rhythmic — you can say a word or two, not sentences."]}', NULL, '{"supports":["time"],"base_duration_sec":2400}', '{"substitutions":["cycling-tempo-effort","cycling-hill-climb","cycling-zone2-ride"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_089', 'cycling-tempo-effort', 'Cycling Tempo Effort', 'cardio', '["quads","hamstrings","glutes","cardiovascular_system"]', NULL, '["cardio","low_impact","conditioning","indoor"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["After a 5-minute easy spin warm-up, settle into a ''comfortably hard'' effort — about 75–85% FTP or 7 out of 10 perceived effort.","Maintain this tempo for 15–30 minutes, then cool down with 5 minutes easy spinning.","Breathe rhythmically and check in on your cadence (aim for 85–95 rpm)."],"cues":["💡 Tempo = you can speak 2–3 words, not full sentences.","Focus on a smooth, powerful pedal stroke — no dead spots at top or bottom."]}', NULL, '{"supports":["time"],"base_duration_sec":2100}', '{"substitutions":["cycling-zone2-ride","cycling-sweet-spot","cycling-intervals-indoor"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_088', 'cycling-zone2-ride', 'Zone 2 Cycling Ride', 'cardio', '["quads","hamstrings","glutes","calves","cardiovascular_system"]', NULL, '["cardio","low_impact","zone2","conditioning","indoor","quiet"]', '["road_bike","mountain_bike","indoor_bike","exercise_bike"]', NULL, '{"steps":["Set resistance so you are pedalling at 80–90 rpm at a cadence that feels like a 4–5 out of 10 effort.","Maintain this steady, conversational pace for the full duration.","If using a smart trainer: target 55–70% of FTP. On a road/exercise bike: you should be able to speak in full sentences."],"cues":["💡 Zone 2 builds your aerobic engine — more base = faster everything else later.","Nasal-only breathing is a useful real-time check that you''re in the zone."]}', NULL, '{"supports":["time"],"base_duration_sec":2400}', '{"substitutions":["steady-indoor-cycle","stationary-bike-steady","cycling-tempo-effort"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_033', 'dead-hang', 'Dead Hang', 'strength', '["shoulder_girdle","grip","forearms","spine"]', NULL, '["strength","mobility","low_impact","no_floor","shoulder_health","loads_shoulder"]', '["pull_up_bar"]', NULL, '{"steps":["Grab the bar with both hands just wider than shoulder-width, palms facing away.","Let your body hang fully — allow your shoulders to rise toward your ears (passive hang) or actively depress them (active hang).","Breathe steadily, hold for the prescribed duration, then step down."],"cues":["💡 Passive hang decompresses the spine. Active hang builds shoulder stability. Both are useful.","Build grip strength progressively — start with 20-second holds."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["scapular-retraction-hang","pull-up"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_047', 'deep-squat-hold', 'Deep Squat Hold (Malasana)', 'mobility', '["hip_flexors","adductors","ankles","glutes","spine"]', NULL, '["mobility","low_impact","floor","pregnancy_safe"]', '["none"]', NULL, '{"steps":["Stand with feet slightly wider than shoulder-width, toes turned out 30-45 degrees. Lower into a full squat — hips below knees — and hold the bottom position.","Press your elbows against the inside of your knees to gently push them outward. Keep your chest up and spine long. Heels should stay flat on the floor.","Hold for the prescribed duration, breathing steadily. If your heels rise, place a folded towel or small weight plate under them while you work on ankle mobility."],"cues":["This position is a baseline of human mobility — if it is uncomfortable, it is a signal that hips, ankles, or thoracic spine need mobility work.","Elbows pressing knees open is both a coaching cue and a stretch — it actively opens the hips from the inside.","💡 💡 Practice daily for 60-second holds. Ankle dorsiflexion is the most common limiting factor — calf stretching and raised heels bridge the gap while you build it."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["ninety-ninety-hip-switch","seated-butterfly","half-kneeling-hip-opener"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_003', 'dumbbell-arnold-press', 'Dumbbell Arnold Press', 'strength', '["anterior_deltoid","medial_deltoid","triceps","upper_traps"]', NULL, '["strength","dumbbell","push","no_floor","low_impact","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Sit or stand holding two dumbbells at shoulder height, palms facing your face — as if you just finished a bicep curl.","Press the weights overhead while rotating your palms to face forward. Finish with arms fully extended above your head.","Reverse: lower back to the start position, rotating palms back toward your face. That is one rep."],"cues":["💡 The rotation is the whole point — it recruits all three heads of the deltoid, not just the front like a standard press.","Brace your core at the top. Avoid arching your lower back as the dumbbells reach full extension."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-shoulder-press","dumbbell-seated-overhead-press"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_002', 'dumbbell-bent-over-row', 'Dumbbell Bent-Over Row', 'strength', '["lats","rhomboids","rear_deltoid","biceps","erector_spinae"]', NULL, '["strength","dumbbell","pull","low_impact","loads_lower_back"]', '["dumbbell"]', NULL, '{"steps":["Stand with feet shoulder-width, hinge at the hips until your torso is near parallel to the floor, knees soft. Hold both dumbbells with a neutral grip.","Row both dumbbells to your lower ribcage simultaneously, driving elbows behind you. Squeeze your upper back hard at the top.","Lower with full control — do not let gravity win the eccentric portion."],"cues":["💡 Your lower back is bracing isometrically the whole time — engage your core before every rep.","If you are bouncing or jerking, the weight is too heavy. Controlled rows build more muscle."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-arm-row","band-row-seated"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_005', 'dumbbell-bulgarian-split-squat', 'Dumbbell Bulgarian Split Squat', 'strength', '["quads","glutes","hamstrings","hip_flexors"]', NULL, '["strength","dumbbell","low_impact","unilateral","floor","loads_knee"]', '["dumbbell"]', NULL, '{"steps":["Stand in front of a bench or chair. Place your rear foot on it, laces down. Hold a dumbbell in each hand. Step your front foot forward far enough that your shin stays close to vertical when you descend.","Lower your rear knee toward the floor by bending your front knee. Keep your torso tall throughout — resist the urge to lean forward.","Drive up through your front heel to full hip extension. That is one rep. Complete all reps on one side before switching."],"cues":["💡 Most of the work should be felt in the front leg glute and quad. If you feel it mainly in your knee, step your front foot further forward.","This is a balance challenge as much as a strength exercise — go light until you own the position."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-lunge","reverse-lunge","dumbbell-side-lunge"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_011', 'dumbbell-chest-press-floor', 'Dumbbell Floor Chest Press', 'strength', '["pectorals","triceps","anterior_deltoid"]', NULL, '["strength","dumbbell","push","floor","low_impact","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Lie flat on the floor holding dumbbells above your chest, palms facing forward, upper arms resting on the floor.","Lower the dumbbells until your upper arms touch the floor, pausing briefly. Keep your wrists stacked over your elbows throughout.","Press back up explosively, stopping just before full elbow lockout to keep tension in the chest."],"cues":["💡 The pause at the bottom removes stored elastic energy — every rep starts from nothing, making this harder and more effective than a bench press.","Keep your lower back flat on the floor throughout. No arching."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-incline-chest-press","dumbbell-floor-chest-fly"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_012', 'dumbbell-concentration-curl', 'Dumbbell Concentration Curl', 'strength', '["biceps_brachii"]', NULL, '["strength","dumbbell","pull","no_floor","low_impact"]', '["dumbbell"]', NULL, '{"steps":["Brace your working arm elbow against the inside of your thigh. Hold the dumbbell hanging straight down, arm fully extended.","Curl the dumbbell toward your shoulder, keeping your upper arm completely still — only your forearm moves. Squeeze hard at the top.","Lower with full control until your arm is fully extended. Complete all reps, then switch sides."],"cues":["💡 Bracing your elbow on your thigh eliminates swinging — it is all bicep, all the time.","Slow down the lowering phase — the eccentric builds as much strength as the curl up."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-bicep-curl","dumbbell-hammer-curl","band-bicep-curl"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_010', 'dumbbell-floor-chest-fly', 'Dumbbell Floor Chest Fly', 'strength', '["pectorals","anterior_deltoid"]', NULL, '["strength","dumbbell","push","floor","low_impact","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Lie flat on the floor holding a dumbbell in each hand above your chest. Maintain a slight, permanent bend in your elbows — never fully straight.","Open your arms wide, lowering in an arc until your upper arms touch the floor. Feel the stretch across your chest.","Squeeze your chest to bring the dumbbells back together above your sternum, following the same arc."],"cues":["💡 The floor acts as a natural depth stop — your arms cannot drop past it, which protects your shoulder joint.","Think hugging a large barrel: the motion is an arc, not a press. Chest drives it, not arms."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-incline-chest-press","dumbbell-chest-press-floor"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_004', 'dumbbell-goblet-squat', 'Dumbbell Goblet Squat', 'strength', '["quads","glutes","core","adductors"]', NULL, '["strength","dumbbell","low_impact","full_body","floor","loads_knee"]', '["dumbbell"]', NULL, '{"steps":["Hold one dumbbell vertically at your chest — both hands cupping the top end.","Stand feet shoulder-width, toes angled out 15–30°. Squat down keeping the dumbbell close to your chest.","Drive through your heels to stand, squeezing your glutes at the top."],"cues":["💡 Chest stays tall — the weight counterbalances you into a deep squat.","Knees track over toes throughout — push them out if they cave."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-sumo-deadlift","sumo-squat","kettlebell-goblet-squat"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_006', 'dumbbell-hip-thrust', 'Dumbbell Hip Thrust', 'strength', '["glutes","hamstrings","core"]', NULL, '["strength","dumbbell","low_impact","floor","glutes"]', '["dumbbell"]', NULL, '{"steps":["Sit on the floor with your upper back against a bench, shoulder blades on the edge. Place a dumbbell horizontally across your hips. Feet flat, hip-width apart.","Drive through your heels to push your hips up until your body forms a straight line from knees to shoulders. Squeeze your glutes hard at the top.","Lower your hips back toward the floor with control. That is one rep."],"cues":["💡 The glute squeeze at the top is the whole exercise — a half-contracted glute produces half the benefit.","Tuck your chin slightly and brace your core to avoid over-extending your lower back."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["supported-glute-bridge","single-leg-glute-bridge"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_009', 'dumbbell-renegade-row', 'Dumbbell Renegade Row', 'strength', '["lats","core","triceps","rear_deltoid"]', NULL, '["strength","dumbbell","pull","core","floor","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Get into a high plank with a dumbbell under each hand. Feet wider than hip-width for stability. Body forms a straight line from head to heels.","Row one dumbbell to your hip while pressing the other into the floor. Keep your hips completely level — resist any rotation or tilting.","Return the dumbbell to the floor, then row the other side. Both sides equal one rep."],"cues":["💡 The anti-rotation demand is the real exercise here. A wobbling hip means your core, not your back, is the limiting factor.","Go lighter than you expect. This is not a heavy rowing movement — it is a plank with a row attached."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-arm-row","plank-shoulder-tap"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_013', 'dumbbell-reverse-curl', 'Dumbbell Reverse Curl', 'strength', '["brachialis","brachioradialis","forearms"]', NULL, '["strength","dumbbell","pull","no_floor","low_impact"]', '["dumbbell"]', NULL, '{"steps":["Stand tall holding dumbbells with an overhand grip (palms facing down), arms fully extended at your sides.","Curl both dumbbells toward your shoulders, keeping elbows fixed at your sides. The palms-down grip targets the brachialis and forearms more than a standard curl.","Lower slowly — the eccentric with an overhand grip is demanding. Reach full extension between every rep."],"cues":["💡 Weaker here than in a standard curl? Good — you have found a real weak link. This builds forearm thickness most people neglect.","Keep your wrists neutral — do not let them roll under during the curl."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-bicep-curl","dumbbell-hammer-curl"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_014', 'dumbbell-side-lunge', 'Dumbbell Lateral Lunge', 'strength', '["adductors","glutes","quads"]', NULL, '["strength","dumbbell","low_impact","unilateral","no_floor","loads_knee"]', '["dumbbell"]', NULL, '{"steps":["Stand tall holding a dumbbell at your side. Step wide out to one side, keeping toes pointing forward or slightly out on both feet.","Bend the stepping knee and sit into that hip. Keep the opposite leg straight. Let the dumbbell hang beside the bent knee.","Push off the bent foot to return to standing. Complete all reps on one side, then switch."],"cues":["💡 The lateral motion demands hip abductor strength and inner thigh flexibility — two things most training programs completely miss.","Keep your back flat and chest up as you sit into the lunge. If you round forward, the weight is too heavy."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["lateral-lunge","dumbbell-lunge","curtsy-lunge"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_001', 'dumbbell-single-arm-row', 'Dumbbell Single-Arm Row', 'strength', '["lats","rhomboids","rear_deltoid","biceps"]', NULL, '["strength","dumbbell","pull","no_floor","low_impact","loads_lower_back"]', '["dumbbell"]', NULL, '{"steps":["Place your left hand and left knee on a bench for support. Hold the dumbbell in your right hand, arm hanging straight below your shoulder.","Row the dumbbell to your hip, keeping your elbow close to your torso. At the top your upper arm should be roughly parallel to the floor.","Lower slowly until your arm is fully extended. Complete all reps, then switch sides."],"cues":["💡 Keep your working shoulder level — do not let it rotate up to help the lift.","Elbow to pocket, not elbow to ceiling. The lat does the pulling, not the shoulder."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-bent-over-row","band-row-seated"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_007', 'dumbbell-single-leg-rdl', 'Dumbbell Single-Leg Romanian Deadlift', 'strength', '["hamstrings","glutes","erector_spinae"]', NULL, '["strength","dumbbell","low_impact","unilateral","posterior_chain","loads_lower_back"]', '["dumbbell"]', NULL, '{"steps":["Stand tall holding a dumbbell in one or both hands. Shift your weight onto one leg, keeping a soft bend in that knee.","Hinge forward at the hip, letting the dumbbell travel down your standing leg as your non-working leg extends behind you. Keep your hips square — resist rotating.","Return to standing by driving through your heel and squeezing your glute at the top. That is one rep."],"cues":["💡 Think of your back leg and torso as one rigid plank — they move together as a unit, not independently.","The range ends where your hip rotation starts. Do not chase extra depth at the cost of a square pelvis."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-romanian-deadlift","kettlebell-single-leg-rdl","good-morning-bodyweight"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_015', 'dumbbell-suitcase-carry', 'Dumbbell Suitcase Carry', 'strength', '["obliques","core","hip_flexors","traps","forearms"]', NULL, '["strength","dumbbell","core","low_impact","no_floor"]', '["dumbbell"]', NULL, '{"steps":["Hold a single dumbbell in one hand at your side — suitcase style. Stand tall with shoulders level and equal.","Walk forward for the prescribed distance or time, resisting any side-bend toward the weight. Keep your core braced, eyes forward, breathing steady.","At the halfway point, switch hands and return."],"cues":["💡 The challenge is resisting the lean — the moment you tip toward the weight, your core has lost the battle.","Slower and heavier beats fast and light. A loaded carry is a posture and bracing exercise, not a conditioning sprint."]}', NULL, '{"supports":["time"],"base_duration_sec":40}', '{"substitutions":["dumbbell-farmers-walk","dumbbell-wood-chop"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_008', 'dumbbell-upright-row', 'Dumbbell Upright Row', 'strength', '["medial_deltoid","upper_traps","biceps"]', NULL, '["strength","dumbbell","pull","no_floor","low_impact","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Hold dumbbells in front of your thighs, palms facing you, hands close together.","Pull the dumbbells straight up along your body, elbows leading and flaring out to the sides.","Stop when elbows reach shoulder height, then lower slowly."],"cues":["💡 Elbows must stay higher than wrists throughout the movement.","Keep the range of motion comfortable — stop if you feel shoulder impingement."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-lateral-raise","dumbbell-shrug"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_082', 'fartlek-run', 'Fartlek Run', 'cardio', '["cardiovascular_system","quads","hamstrings","calves"]', NULL, '["cardio","high_impact","hiit","conditioning","outdoor","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Start with a 5-minute easy jog warm-up.","Pick a landmark ahead (lamp post, tree, corner) and run hard to it, then jog easy until fully recovered.","Repeat the hard/easy cycle for the session, varying effort and distance randomly."],"cues":["💡 Fartlek (Swedish for ''speed play'') — unstructured intervals that build both speed and endurance.","The recovery should be genuinely easy — not a moderate jog."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["run-intervals-outdoor","tempo-run-outdoor","zone2-easy-run"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_060', 'foam-roll-calves', 'Foam Roll: Calves', 'recovery', '["gastrocnemius","soleus","achilles_tendon"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Sit on the floor, roller under your calves. Hands behind you for support.","Lift your hips and roll from ankle to just below the knee, pausing on tight spots.","Cross one ankle over the other to increase pressure on one calf at a time."],"cues":["💡 Rotate your foot in and out to reach different angles of the calf muscle.","Essential after running or cycling — tight calves contribute to heel and knee pain."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["calf-stretch-wall","ankle-mobility-circles","foam-roll-quads"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_061', 'foam-roll-glutes', 'Foam Roll: Glutes', 'recovery', '["gluteus_maximus","piriformis"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Sit on the foam roller, shifted to one side. Cross your right ankle over your left knee to target the right glute.","Lean into the right side and roll back and forth over the glute, pausing on tight spots.","Switch sides after 45 seconds."],"cues":["💡 The piriformis (deep glute) is often the real culprit in hip and back tightness.","More body weight = more pressure. Use your hands to lift slightly if too intense."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["supine-figure-four","glute-piriformis-stretch","foam-roll-it-band"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_064', 'foam-roll-hamstrings', 'Foam Roll: Hamstrings', 'recovery', '["hamstrings","biceps_femoris"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Sit on the floor, roller under the back of one thigh. Hands behind for support, other leg crossed over for extra pressure.","Roll from just above the knee to just below the glute, pausing on tight spots.","Rotate your leg in and out to hit different fibers."],"cues":["💡 The bulk of the hamstring is in the middle of the thigh — spend most time there.","Crossing one leg over the other doubles the pressure — use this when you need it."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["lying-hamstring-stretch","seated-hamstring-stretch","foam-roll-calves"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_062', 'foam-roll-hip-flexors', 'Foam Roll: Hip Flexors', 'recovery', '["psoas","iliacus","rectus_femoris"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Lie face down. Position the foam roller under your right hip crease area (just below the pelvis, where the hip flexor meets the thigh).","Prop yourself on your forearms and slowly explore the area just inside and below the hip bone.","Pause on tight spots and breathe. Gently bend and extend your knee to add active pressure release."],"cues":["💡 This is a small, targeted area — move slowly, the tissue is deep.","High-value for runners, cyclists, and anyone who sits for long periods."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["couch-stretch","hip-flexor-stretch","foam-roll-quads"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_058', 'foam-roll-it-band', 'Foam Roll: IT Band', 'recovery', '["iliotibial_band","tensor_fasciae_latae","vastus_lateralis"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Lie on your side, foam roller under your outer thigh. Support yourself on one forearm, top foot on the floor for stability.","Roll slowly from just above the knee to just below the hip — go slow; this area is often very sensitive.","Pause on tight spots, breathe, and allow the tissue to release before moving on."],"cues":["💡 The IT band itself doesn''t need direct pressure — you''re targeting the muscles that attach to it.","If too painful, stack both feet on the floor to reduce pressure."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["foam-roll-quads","glute-piriformis-stretch","band-lateral-walk"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_063', 'foam-roll-lats', 'Foam Roll: Lats', 'recovery', '["latissimus_dorsi","teres_major"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Lie on your side, roller under your armpit area. Extend the bottom arm overhead.","Roll slowly from just below the armpit to mid-rib cage, pausing on tight spots.","Rotate slightly forward to reach the serratus and rear shoulder area. Switch sides."],"cues":["💡 Tight lats pull the shoulder forward and limit overhead range — rolling here has big payoff.","Straighten and flex your elbow while on a tight spot for active release."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["foam-roll-upper-back","chest-opener-arms","dead-hang"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_057', 'foam-roll-quads', 'Foam Roll: Quads', 'recovery', '["quadriceps","rectus_femoris"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Lie face down, foam roller under your thighs. Support yourself on your forearms.","Roll slowly from the top of your knee to just below your hip, pausing on any tight spots for 10–20 seconds.","Turn 30° to one side to target the outer quad (vastus lateralis), then the inner quad."],"cues":["💡 Breathe through tight spots instead of rolling off them.","Overlap each pass slightly — systematic coverage beats random rolling."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["foam-roll-it-band","side-lying-quad-stretch","foam-roll-hip-flexors"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_059', 'foam-roll-upper-back', 'Foam Roll: Upper Back', 'recovery', '["thoracic_spine","rhomboids","erector_spinae"]', NULL, '["recovery","low_impact","floor"]', '["foam_roller"]', NULL, '{"steps":["Sit in front of the foam roller and lean back onto it so it''s positioned across your mid-back.","Support your head with your hands. Gently extend over the roller, opening your chest.","Shift the roller one segment at a time from mid-back toward the top of your shoulder blades."],"cues":["💡 Do not roll the lower back or neck — mid and upper thoracic only.","This is one of the best antidotes to desk posture — spend extra time here."]}', NULL, '{"supports":["time"],"base_duration_sec":90}', '{"substitutions":["thoracic-extension-chair","active-thoracic-rotation","cat-cow-flow"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_032', 'hanging-leg-raise', 'Hanging Leg Raise', 'strength', '["rectus_abdominis","hip_flexors","core"]', NULL, '["strength","core","low_impact","no_floor","loads_shoulder"]', '["pull_up_bar"]', NULL, '{"steps":["Hang from the bar with both hands, arms fully extended. Brace your core to prevent swinging.","Keeping your legs straight (or bent for easier variation), raise them until parallel to the floor or higher.","Lower slowly — don''t let momentum swing your legs back down."],"cues":["💡 Posterior pelvic tilt as you raise — curl your tailbone up to fully engage the abs.","Bent knees = easier, straight legs = harder. Master bent before going straight."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["v-up","dead-bug","hollow-body-hold"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_066', 'happy-baby-pose', 'Happy Baby Pose', 'recovery', '["hip_flexors","adductors","lower_back"]', NULL, '["recovery","mobility","low_impact","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on your back. Draw both knees toward your chest, then open them wide toward the armpits.","Flex your feet and grab the outside edges of each foot (or your ankles or shins if needed).","Gently pull down, drawing the knees toward the floor beside your torso. Rock side to side if it feels good."],"cues":["💡 This is a restorative pose — let gravity do the work over a long hold.","One of the best post-run or post-leg-day hip openers."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["supine-knee-to-chest","seated-butterfly","ninety-ninety-hip-switch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_083', 'hill-repeats-running', 'Hill Repeats', 'cardio', '["quads","glutes","calves","cardiovascular_system","hamstrings"]', NULL, '["cardio","high_impact","hiit","conditioning","outdoor","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Find a moderate hill (5–8% gradient, 50–150 m long). Jog 5 minutes easy to the base as your warm-up.","Run up the hill at 85–90% effort, focusing on driving your knees and pumping your arms.","Walk or jog back down as recovery. Repeat for the prescribed number of reps."],"cues":["💡 Uphill running builds leg strength and VO2 max faster than flat running.","Lean slightly forward from the ankle, not the waist — keeps form efficient."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["run-intervals-outdoor","fartlek-run","power-step-up-jump"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_035', 'hollow-body-hold', 'Hollow Body Hold', 'strength', '["rectus_abdominis","hip_flexors","core"]', NULL, '["strength","core","low_impact","floor"]', '["none"]', NULL, '{"steps":["Lie on your back, arms extended overhead. Press your lower back flat into the floor.","Lift your arms, head, and legs simultaneously — legs straight, toes pointed, lower back stays flat.","Hold this banana-shaped position. Lower everything if your back lifts off the floor."],"cues":["💡 The test: you should be able to slide a hand under your lower back — if you can, you''ve broken form.","Start with legs higher (easier) and progress toward parallel over time."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["v-up","dead-bug","modified-plank"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_039', 'inverted-row-table', 'Inverted Row (Under Table)', 'strength', '["lats","rhomboids","rear_deltoid","biceps"]', NULL, '["strength","pull","low_impact","floor"]', '["none"]', NULL, '{"steps":["Lie under a sturdy table, grip the edge with both hands roughly shoulder-width apart.","Keeping your body in a straight line from head to heels, pull your chest up to the table edge.","Lower slowly until your arms are straight."],"cues":["💡 The more horizontal your body, the harder it is — start with knees bent for more upright angle.","The table version is a genuine pull-up alternative for those without a bar."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["pull-up","band-row-seated","dumbbell-bent-over-row"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_070', 'jumping-jack', 'Jumping Jack', 'cardio', '["cardiovascular_system","calves","shoulders","hip_abductors"]', NULL, '["cardio","high_impact","bodyweight","dynamic","no_floor","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand with feet together, arms at your sides.","Jump your feet out to shoulder width while simultaneously raising your arms overhead.","Jump your feet back together and lower your arms. That is one rep."],"cues":["💡 Land softly with slightly bent knees — protect your joints.","For low-impact: step side to side instead of jumping."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["low-impact-jumping-jacks","high-knees","march-in-place"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_029', 'kettlebell-deadlift', 'Kettlebell Deadlift', 'strength', '["hamstrings","glutes","erector_spinae","traps","forearms"]', NULL, '["strength","low_impact","posterior_chain","full_body","loads_lower_back"]', '["kettlebell"]', NULL, '{"steps":["Stand with the kettlebell between your feet, feet just wider than shoulder-width. Hinge at the hips to grip it with both hands — flat back, hips above knees, chest up.","Push the floor away with your legs while driving your hips forward. Keep the bell close to your body as it rises — it should travel up your shins.","Stand tall at the top: hips and knees locked, core tight. Lower by hinging first, then bending the knees. Set the bell down under control."],"cues":["💡 This is a hinge, not a squat. Your hips descend back and behind you, not straight down.","Keep the bell directly over the mid-foot throughout. A bell that drifts forward puts unnecessary strain on your lower back."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-deadlift","dumbbell-romanian-deadlift","kettlebell-swing"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_025', 'kettlebell-goblet-squat', 'Kettlebell Goblet Squat', 'strength', '["quads","glutes","core","adductors"]', NULL, '["strength","low_impact","full_body","loads_knee"]', '["kettlebell"]', NULL, '{"steps":["Hold the kettlebell vertically with both hands cupping the top of the bell at your chest. Stand with feet shoulder-width, toes angled out 15 to 30 degrees.","Squat down with the kettlebell close to your chest — its weight counterbalances you and pulls you into a deep, upright position.","Drive through your heels to stand, squeezing your glutes at the top. That is one rep."],"cues":["💡 The goblet position forces an upright torso and deep hip flexion — this is one of the best teaching tools for a perfect squat pattern.","Knees track over toes throughout. If they cave in, use your elbows to push them out on the way down."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-goblet-squat","sumo-squat","band-squat"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_027', 'kettlebell-halo', 'Kettlebell Halo', 'strength', '["anterior_deltoid","medial_deltoid","triceps","rotator_cuff","core"]', NULL, '["strength","mobility","low_impact","no_floor","shoulder_health"]', '["kettlebell"]', NULL, '{"steps":["Hold the kettlebell with both hands at chest height, arms slightly bent. Stand with feet shoulder-width.","Move the bell in a circular path around your head: left side, over the top, right side, and back to start. Keep the circle controlled and close to your head.","Complete the prescribed reps, then reverse direction for the same number."],"cues":["💡 The halo challenges shoulder mobility and stability simultaneously — go slow enough to feel the control demand.","Keep your core braced and avoid leaning. If you are tilting to follow the bell, slow down."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-arnold-press","shoulder-circles"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_026', 'kettlebell-single-arm-press', 'Kettlebell Single-Arm Press', 'strength', '["anterior_deltoid","triceps","core"]', NULL, '["strength","push","low_impact","no_floor","core","loads_shoulder"]', '["kettlebell"]', NULL, '{"steps":["Clean the kettlebell to the rack position: bell resting on your forearm, elbow close to your body, wrist neutral, fist at shoulder height.","Press straight up until your arm is fully locked out overhead. Keep your core braced and avoid side-bending.","Lower the bell back to the rack position with control. Complete all reps, then switch sides."],"cues":["💡 The rack position is a skill in itself — the bell should rest on your forearm, not dangle from your wrist.","A single-arm press reveals any imbalance between sides immediately. Start with your weaker arm."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-shoulder-press","dumbbell-arnold-press","band-overhead-press"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_028', 'kettlebell-single-leg-rdl', 'Kettlebell Single-Leg RDL', 'strength', '["hamstrings","glutes","erector_spinae"]', NULL, '["strength","low_impact","unilateral","posterior_chain","loads_lower_back"]', '["kettlebell"]', NULL, '{"steps":["Stand tall holding the kettlebell in one hand at your side. Shift your weight to the opposite leg, soft bend in the knee.","Hinge at the hip, letting the kettlebell travel down your standing leg as your non-working leg extends behind you. Hips stay square.","Return to standing by driving through your heel and squeezing your glute. That is one rep. Complete all reps, then switch sides."],"cues":["💡 Think of your back leg and torso as a single rigid plank — they rotate as one unit around your hip joint.","The range ends where your pelvis rotates. Quality over depth: a square hip at 45 degrees beats a rotated hip at 90."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-leg-rdl","dumbbell-romanian-deadlift"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_024', 'kettlebell-swing', 'Kettlebell Swing', 'strength', '["glutes","hamstrings","erector_spinae","core","shoulders"]', NULL, '["strength","cardio","low_impact","full_body","posterior_chain","loads_lower_back"]', '["kettlebell"]', NULL, '{"steps":["Stand with feet slightly wider than shoulder-width, kettlebell on the floor between your feet.","Hinge at the hips, grab the bell and hike it back between your legs. Then explosively drive your hips forward to send the bell swinging to shoulder height.","Let the bell fall back, hinging your hips to receive it — don''t squat, hinge."],"cues":["💡 The power is a hip snap, not a shoulder lift — your arms are just the cable.","Squeeze your glutes hard at the top like you''re trying to crack a walnut."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-romanian-deadlift","good-morning-bodyweight","dumbbell-hip-thrust"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_076', 'lateral-shuffle-drill', 'Lateral Shuffle Drill', 'cardio', '["glute_medius","quads","calves","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","agility","dynamic","no_floor","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand in an athletic stance, knees slightly bent, weight on the balls of your feet.","Shuffle quickly to the right for 4–5 steps by pushing off your left foot.","Immediately shuffle back to the left. Keep your hips low and your feet never crossing."],"cues":["💡 The lower you stay, the more glute and quad activation you get.","Hips face forward the whole time — this is a lateral movement, not a rotation."]}', NULL, '{"supports":["time"],"base_duration_sec":40}', '{"substitutions":["shuffle-tap","grapevine-step","band-lateral-walk"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_045', 'leg-swings-front-back', 'Active Leg Swings (Front/Back)', 'mobility', '["hip_flexors","hamstrings","glutes"]', NULL, '["mobility","low_impact","no_floor","dynamic"]', '["none"]', NULL, '{"steps":["Stand sideways to a wall, one hand touching for balance. Shift weight to the inner leg.","Swing the outer leg forward and back in a relaxed pendulum motion — gradually increasing the range.","After reps, turn and repeat on the other side."],"cues":["💡 Relaxed, not forced — let momentum build the range over successive swings.","Active warm-up for running, cycling, or any lower-body session."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["leg-swings-lateral","hip-flexor-stretch","couch-stretch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_046', 'leg-swings-lateral', 'Active Leg Swings (Side to Side)', 'mobility', '["hip_abductors","adductors","glute_medius"]', NULL, '["mobility","low_impact","no_floor","dynamic"]', '["none"]', NULL, '{"steps":["Face a wall, both hands lightly touching for balance. Weight on one foot.","Swing the free leg across your body and then out to the side in a wide arc.","Keep the movement controlled at the extremes — let momentum build gradually."],"cues":["💡 Swing from the hip, not the knee — think wide arc from the pelvis.","Particularly useful before lateral sports and hip-heavy strength training."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["leg-swings-front-back","ninety-ninety-hip-switch","band-lateral-walk"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_054', 'lunge-thoracic-rotation', 'Lunge with Thoracic Rotation', 'mobility', '["hip_flexors","thoracic_spine","obliques","glutes"]', NULL, '["mobility","low_impact","floor","dynamic"]', '["none"]', NULL, '{"steps":["Step into a lunge, front foot flat, rear knee on or near the floor.","Place both hands on your front thigh. Rotate your torso toward the front leg, reaching the top arm toward the ceiling.","Return to centre and alternate sides each rep."],"cues":["💡 This is one of the best single mobility exercises — hits hip flexors AND thoracic at once.","Move with your breath: inhale to stand tall, exhale to rotate further."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["world-greatest-stretch","active-thoracic-rotation","cat-cow-flow"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_051', 'lying-hamstring-stretch', 'Lying Hamstring Stretch', 'mobility', '["hamstrings","calves"]', NULL, '["mobility","low_impact","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on your back. Bend one knee with foot flat. Extend the other leg and lift it, clasping behind the thigh.","Gently pull the leg toward you until you feel a comfortable stretch along the back of the thigh.","Flex your foot (toes toward your shin) to add calf and sciatic nerve stretch. Hold and switch sides."],"cues":["💡 Keep your lower back flat — don''t let it arch off the floor.","Breathing into the stretch and relaxing on the exhale helps the muscle release further."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["seated-hamstring-stretch","standing-hamstring-stretch","standing-forward-fold"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_056', 'neck-half-circles', 'Neck Half-Circles', 'mobility', '["cervical_spine","upper_trapezius","sternocleidomastoid"]', NULL, '["mobility","low_impact","no_floor","pregnancy_safe","postnatal_safe","quiet"]', '["none"]', NULL, '{"steps":["Sit or stand tall. Drop your right ear toward your right shoulder, feeling the stretch on the left side.","Slowly roll your chin forward toward your chest, continuing to the left ear down to the left shoulder.","Reverse the arc back to neutral. Never complete a full circle by taking the head back — that compresses the cervical spine."],"cues":["💡 Front semicircle only — half-circles are safe, full circles backward are not.","Breathe into each stretch position and let the weight of your head do the work."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["neck-stretch","shoulder-roll-stretch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_042', 'ninety-ninety-hip-switch', '90/90 Hip Switch', 'mobility', '["hip_external_rotators","hip_internal_rotators","glutes","adductors"]', NULL, '["mobility","low_impact","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Sit on the floor with both knees bent at 90 degrees — one leg in front of you (shin perpendicular to your torso), one leg to the side (shin parallel to your torso). Sit tall with a neutral spine.","Rotate both knees to the opposite side simultaneously — the front leg becomes the back leg and vice versa. Your hips pivot as you switch.","Pause briefly in the new position, sitting as tall as possible before switching back. That is one rep."],"cues":["Keep the rotation driven from your hips, not from leaning your torso — the goal is hip mobility, not body sway.","If you cannot get both shins to the floor without pain, sit on a folded blanket to reduce the hip angle demand.","💡 💡 This exercise builds the internal and external hip rotation range that protects the hips and lower back long-term. Slow and intentional is far more effective than fast reps."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["half-kneeling-hip-opener","pigeon-pose","couch-stretch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_038', 'nordic-hamstring-curl', 'Nordic Hamstring Curl', 'strength', '["hamstrings","glutes"]', NULL, '["strength","posterior_chain","floor","low_impact"]', '["chair"]', NULL, '{"steps":["Kneel on a mat with a partner holding your ankles — or hook your heels under a heavy sofa or secured bar.","With your body upright, lower your torso toward the floor as slowly as you can.","Catch yourself with your hands, then push back up to the kneeling position."],"cues":["💡 The eccentric (lowering) phase is where the hamstring strength is built — make it slow.","This is hard. Even 3–5 slow reps builds significant hamstring resilience."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-leg-rdl","good-morning-bodyweight","dumbbell-romanian-deadlift"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_041', 'pistol-squat-assist', 'Assisted Pistol Squat', 'strength', '["quads","glutes","hip_flexors","core"]', NULL, '["strength","low_impact","unilateral","floor","loads_knee"]', '["chair"]', NULL, '{"steps":["Stand in front of a chair or wall for balance. Extend one leg in front of you, slightly bent.","Lower yourself slowly on the standing leg until you tap the chair or reach your comfortable depth — keep the elevated leg straight.","Drive through the standing heel to rise back to standing."],"cues":["💡 Holding a counterweight (light dumbbell) actually makes balancing easier.","This is a skill as much as a strength exercise — patience with the progression."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-bulgarian-split-squat","reverse-lunge","lateral-lunge"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_078', 'power-step-up-jump', 'Power Step-Up (Explosive)', 'cardio', '["quads","glutes","calves","cardiovascular_system"]', NULL, '["cardio","high_impact","bodyweight","power","dynamic","loads_knee","loads_ankle"]', '["chair"]', NULL, '{"steps":["Stand in front of a sturdy step or box. Place your right foot on the step.","Drive through the right heel to step up explosively, driving your left knee high at the top.","Land softly back on the floor and immediately repeat. Alternate lead legs."],"cues":["💡 The drive comes from the heel of the working leg — not a toe push.","Land with bent knees to absorb impact — quiet landings protect joints."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["box-step-up","jump-squat","broad-jump"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_067', 'progressive-relaxation-body', 'Progressive Muscle Relaxation', 'recovery', '["whole_body"]', NULL, '["recovery","breathing","quiet","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie down comfortably. Starting at your feet, tense each muscle group for 5 seconds, then release completely for 10 seconds.","Work up the body in sequence: feet → calves → thighs → glutes → abdomen → hands → forearms → shoulders → face.","Finish with 2 minutes of complete stillness."],"cues":["💡 The contrast between tension and release teaches your nervous system what ''fully relaxed'' actually feels like.","If you fall asleep, that''s fine — your body needed it."]}', NULL, '{"supports":["time"],"base_duration_sec":600}', '{"substitutions":["body-scan-meditation","tension-release-visualization","mindful-body-check"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_030', 'pull-up', 'Pull-Up', 'strength', '["lats","rhomboids","rear_deltoid","biceps","core"]', NULL, '["strength","pull","low_impact","no_floor","loads_shoulder"]', '["pull_up_bar"]', NULL, '{"steps":["Hang from the bar with a pronated grip (palms away) just wider than shoulder-width.","Pull your body up until your chin clears the bar — lead with your chest, not your chin.","Lower slowly over 2–3 seconds until your arms are fully extended."],"cues":["💡 Initiate by depressing your shoulder blades before you bend your elbows.","Full extension at the bottom — no partial reps, every rep from a dead hang."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["chin-up","inverted-row-table","band-row-seated"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_077', 'reverse-lunge-kick', 'Reverse Lunge to Front Kick', 'cardio', '["quads","glutes","hamstrings","hip_flexors","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","balance","dynamic","no_floor","loads_knee"]', '["none"]', NULL, '{"steps":["Stand tall. Step your right foot back into a reverse lunge, lowering your rear knee toward the floor.","Drive through your left foot to stand, immediately bringing your right knee up and extending it into a front kick.","Lower your right foot back down and repeat. Switch legs after reps."],"cues":["💡 The kick is controlled, not a wild flick — squeeze the quad at the top.","Your balance leg works hard — this is a coordination and strength challenge as much as cardio."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["reverse-lunge","alternating-front-kick","lateral-knee-raise"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_040', 'reverse-plank', 'Reverse Plank', 'strength', '["glutes","hamstrings","erector_spinae","triceps","rear_deltoid"]', NULL, '["strength","posterior_chain","low_impact","floor"]', '["none"]', NULL, '{"steps":["Sit on the floor, hands behind you, fingers pointing forward or outward. Feet flat on the floor.","Push through your hands and heels to lift your hips until your body forms a straight line from head to heels.","Hold the position, squeezing your glutes and keeping your chin slightly tucked."],"cues":["💡 A neglected posterior chain exercise — great complement to planks and push-ups.","If wrists hurt, make fists or use push-up handles to stay neutral."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["hollow-body-hold","dumbbell-hip-thrust","supported-glute-bridge"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_094', 'rowing-2k-time-trial', 'Rowing 2K Time Trial', 'cardio', '["legs","back","shoulders","arms","core","cardiovascular_system"]', NULL, '["cardio","strength","full_body","high_intensity","hiit","indoor","low_impact","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Set the monitor to row 2000 metres. Warm up 5 minutes easy, building to a moderate pace.","Row the full 2K at maximal sustained effort. Go out at target pace, hold it through the middle, lift in the last 500 m.","After finishing, easy paddle 5 minutes to recover — your heart rate will be high."],"cues":["💡 Negative split strategy: rows 1000–1500 m feeling controlled, then build from 1500 m onward.","Record your split time and use it as your benchmark for future sessions."]}', NULL, '{"supports":["time"],"base_duration_sec":600}', '{"substitutions":["rowing-intervals","rowing-pyramid-intervals","rowing-steady-state"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_097', 'rowing-power-strokes', 'Rowing Power Strokes', 'cardio', '["legs","back","arms","glutes","core","cardiovascular_system"]', NULL, '["cardio","strength","full_body","high_intensity","hiit","low_impact","indoor","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Row easy for 3 minutes as a warm-up. Then, within each minute, perform 10 strokes at maximum power followed by the rest of the minute easy.","The 10 power strokes should be explosive — push your split significantly lower than normal.","Repeat this 1-minute cycle for 10 minutes. Cool down 2 minutes easy."],"cues":["💡 Count the 10 strokes carefully — after 10, immediately drop back to easy.","This develops raw power without accumulating excessive fatigue."]}', NULL, '{"supports":["time"],"base_duration_sec":780}', '{"substitutions":["rowing-intervals","rowing-pyramid-intervals","rowing-2k-time-trial"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_095', 'rowing-pyramid-intervals', 'Rowing Pyramid Intervals', 'cardio', '["legs","back","arms","core","cardiovascular_system"]', NULL, '["cardio","strength","full_body","high_intensity","hiit","indoor","low_impact","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Warm up 3 minutes easy. Row hard intervals in a pyramid: 30s / 60s / 90s / 2 min / 90s / 60s / 30s.","Rest equals the work interval between each. Hard intervals at near-maximum effort.","Cool down 3 minutes easy."],"cues":["💡 The 2-minute peak is the hardest — pace yourself on the way up so you can sustain it.","Keep the drive sequence correct even at high intensity: legs → back → arms."]}', NULL, '{"supports":["time"],"base_duration_sec":1500}', '{"substitutions":["rowing-intervals","rowing-2k-time-trial","rowing-steady-state"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_096', 'rowing-technique-drill', 'Rowing Technique Drill', 'cardio', '["legs","back","core"]', NULL, '["cardio","skill","full_body","low_impact","indoor","quiet","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Row at a very slow rate (16–18 spm) and low pressure, focusing entirely on sequence: LEGS → BACK → ARMS (drive), then ARMS → BACK → LEGS (recovery).","Pause at three positions: arms only at the finish, halfway up the slide, and at the catch (shins vertical).","After each pause, check your posture before moving to the next segment."],"cues":["💡 Correct sequencing at slow speed becomes automatic at race pace.","This is NOT about getting a cardiovascular workout — quality of movement is everything."]}', NULL, '{"supports":["time"],"base_duration_sec":900}', '{"substitutions":["rowing-steady-state","rowing-pyramid-intervals"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_098', 'rowing-zone2', 'Rowing Zone 2 Steady', 'cardio', '["cardiovascular_system","legs","back","core"]', NULL, '["cardio","zone2","full_body","low_impact","indoor","quiet","loads_lower_back"]', '["rowing_machine"]', NULL, '{"steps":["Set your target split at a pace you can maintain conversationally — about 2:20–2:40 /500 m for beginners, 2:00–2:20 for intermediate.","Row at rate 18–20 strokes per minute. Focus on maintaining consistent split without drift.","Hold this for the full duration. End with 2 minutes of easy paddling."],"cues":["💡 Zone 2 rowing is particularly effective as a full-body aerobic base builder.","Check every 5 minutes that your split hasn''t crept up — if it has, that''s fatigue: adjust."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["rowing-steady-state","rowing-technique-drill","cycling-zone2-ride"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_034', 'scapular-retraction-hang', 'Scapular Pull (Bar Hang)', 'strength', '["lower_traps","serratus_anterior","shoulder_girdle"]', NULL, '["strength","mobility","low_impact","no_floor","shoulder_health","loads_shoulder"]', '["pull_up_bar"]', NULL, '{"steps":["Hang from the bar in a dead hang with arms fully extended.","Without bending your elbows, depress your shoulder blades — your body will rise slightly.","Hold for a second, then let the shoulder blades rise back to the passive hang position."],"cues":["💡 This is a small movement — 2–3 cm rise, not a full pull-up.","Builds the shoulder stability required for safe, strong pull-ups."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dead-hang","pull-up"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_053', 'seated-straddle-stretch', 'Seated Straddle Stretch', 'mobility', '["adductors","hamstrings","hip_flexors"]', NULL, '["mobility","low_impact","floor","pregnancy_safe"]', '["none"]', NULL, '{"steps":["Sit on the floor with legs spread wide in a V shape. Sit tall with a neutral spine.","Hinge forward from the hips (not the waist), keeping your back long as you lower your chest toward the floor.","Hold at your comfortable depth. Walk your hands forward to increase the stretch."],"cues":["💡 Sit on a folded blanket if your hips tip back — this immediately improves your fold.","The goal is hip crease going forward, not spine rounding forward."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["seated-butterfly","seated-hamstring-stretch","seated-spinal-twist"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_055', 'shoulder-circles-active', 'Active Shoulder Circles', 'mobility', '["rotator_cuff","deltoids","trapezius"]', NULL, '["mobility","low_impact","no_floor","dynamic","pregnancy_safe","postnatal_safe","shoulder_health"]', '["none"]', NULL, '{"steps":["Stand with arms at your sides. Begin making small circles forward, gradually increasing the size over 30 seconds.","Reverse the direction — large circles backward for 30 seconds.","Bring arms to a T position and make small backward circles focusing on the rear deltoids."],"cues":["💡 Slow, deliberate circles warm the shoulder capsule better than fast flailing.","Ideal before any upper body session or after a long period of sitting."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["chest-opener-arms","kettlebell-halo","shoulder-roll-stretch"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_074', 'speed-bag-simulation', 'Speed Bag Simulation', 'cardio', '["forearms","deltoids","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","upper_body","dynamic","no_floor","loads_shoulder"]', '["none"]', NULL, '{"steps":["Raise your hands to face level, elbows bent, hands in loose fists in front of you.","Circle your forearms rhythmically in a forward rolling motion — one in front of the other.","Maintain a steady pace for the duration, keeping elbows at chest height."],"cues":["💡 Excellent active recovery that keeps your heart rate up without impact.","Add small lateral footwork to increase intensity and coordination demand."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["shadow-boxing","standing-bicycle","seated-cardio-punch"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_069', 'speed-skater', 'Speed Skater', 'cardio', '["glutes","quads","hip_abductors","calves","cardiovascular_system"]', NULL, '["cardio","high_impact","bodyweight","dynamic","no_floor","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand on one leg with a slight bend. Push off laterally, leaping sideways to land on the opposite foot — swing the free leg behind like a speed skater.","Swing your arms across your body as you leap — same-side arm crosses toward the landing leg.","Land softly with a bent knee and immediately push back in the opposite direction."],"cues":["💡 Land as quietly as possible — soft landings protect the knee and build deceleration strength.","The further the leap, the more lateral power you develop."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["skater-hop","lateral-shuffle-drill","grapevine-step"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_075', 'stair-climb-simulation', 'Stair Climb Simulation', 'cardio', '["quads","glutes","calves","cardiovascular_system"]', NULL, '["cardio","low_impact","bodyweight","dynamic","loads_knee","loads_ankle"]', '["chair"]', NULL, '{"steps":["Stand in front of a step, low box, or bottom stair.","Step up with your right foot, then your left, so you''re standing on the step. Step down right, then left.","Increase pace progressively. Lead with the opposite foot each round."],"cues":["💡 Drive through the heel of the stepping foot — not the toe.","Adding a knee drive as you step up turns this into a full lower-body challenge."]}', NULL, '{"supports":["time"],"base_duration_sec":40}', '{"substitutions":["box-step-up","power-step-up-jump","high-knees"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_084', 'stride-outs', 'Stride Outs', 'cardio', '["quads","hamstrings","calves","neuromuscular_system"]', NULL, '["cardio","high_impact","skill","conditioning","outdoor","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["After a 10-minute easy jog, begin striding: gradually accelerate over 80–100 m to about 90% of your top speed.","Hold 90% for the middle third, then gradually decelerate over the final 30 m.","Walk or jog easily back to the start. Recover fully between strides."],"cues":["💡 Strides teach your neuromuscular system what fast feels like — they improve running economy.","Focus on relaxation at speed: loose hands, soft shoulders, tall posture."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["fartlek-run","run-intervals-outdoor","zone2-easy-run"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_050', 'supine-figure-four', 'Supine Figure-Four Stretch', 'mobility', '["piriformis","glutes","hip_external_rotators"]', NULL, '["mobility","low_impact","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on your back, knees bent, feet flat. Cross your right ankle over your left knee (figure-four shape).","Option A: stay here for a passive stretch. Option B: reach through and pull your left thigh toward you.","Hold, breathing into the stretch. Switch sides."],"cues":["💡 The closer you pull the thigh, the deeper the stretch — move only as far as comfortable.","Effective for piriformis and posterior hip tightness — often the culprit in lower back pain."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["pigeon-pose","glute-piriformis-stretch","standing-figure-four"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_065', 'supine-knee-to-chest', 'Supine Knee-to-Chest', 'recovery', '["lower_back","hip_flexors","glutes"]', NULL, '["recovery","mobility","low_impact","floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie on your back, knees bent, feet flat. Draw one knee toward your chest with both hands.","Hold the stretch in your lower back and hip. Option: gently rock side to side for a massage effect.","Switch legs after 30–45 seconds. For both legs: draw both knees to chest simultaneously."],"cues":["💡 A simple reset for a tight lower back — effective before getting up in the morning.","Keep the opposite leg relaxed and flat — or bend it if your lower back has trouble."]}', NULL, '{"supports":["time"],"base_duration_sec":60}', '{"substitutions":["pigeon-pose","supine-figure-four","legs-up-wall"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_100', 'trail-run-easy', 'Easy Trail Run', 'cardio', '["quads","hamstrings","calves","glutes","cardiovascular_system","proprioception"]', NULL, '["cardio","high_impact","outdoor","conditioning","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Choose a trail suitable for your fitness level — wide, well-maintained paths for beginners.","Run at an easy, conversational effort. Reduce to a walk on uphills; pick it back up on the flat.","Focus on where your feet land — uneven terrain demands present-moment attention."],"cues":["💡 Trail running strengthens the stabilisers around your ankles, knees, and hips faster than road running.","Effort over pace — hills will slow your pace; let them. The effort counts."]}', NULL, '{"supports":["time"],"base_duration_sec":2400}', '{"substitutions":["easy-run-outdoor","zone2-easy-run","fartlek-run"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_086', 'treadmill-hill-run', 'Treadmill Hill Run', 'cardio', '["quads","glutes","calves","cardiovascular_system"]', NULL, '["cardio","high_impact","conditioning","indoor","loads_knee","loads_ankle"]', '["treadmill"]', NULL, '{"steps":["Set the treadmill to 6–10% incline at a moderate speed. Warm up 2 minutes at flat and easy.","Run at this elevation for the duration, focusing on uphill mechanics: driving the knees and pumping the arms.","Every 5 minutes, return to flat for 1 minute to recover."],"cues":["💡 Don''t hold the handrails — it removes most of the cardiovascular benefit.","Incline running builds glutes and calves rapidly; reduce speed compared to flat runs."]}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["treadmill-run-steady","treadmill-intervals","hill-repeats-running"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_085', 'treadmill-intervals', 'Treadmill Speed Intervals', 'cardio', '["cardiovascular_system","quads","hamstrings","calves"]', NULL, '["cardio","high_impact","hiit","conditioning","indoor","loads_knee","loads_ankle"]', '["treadmill"]', NULL, '{"steps":["Warm up 3–4 minutes at an easy walk/jog. Set the speed to a challenging but sustainable pace.","Run at this elevated speed for 30–60 seconds, then reduce to a recovery pace for 90–120 seconds.","Repeat the work/rest cycle for the session duration. Cool down with 2 minutes of walking."],"cues":["💡 Set the pace before you step on — fumbling the controls during an interval is a distraction.","Use 1% incline throughout to better replicate outdoor running effort."]}', NULL, '{"supports":["time"],"base_duration_sec":1200}', '{"substitutions":["run-intervals-outdoor","treadmill-run-steady","treadmill-hill-run"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_036', 'v-up', 'V-Up', 'strength', '["rectus_abdominis","hip_flexors","core"]', NULL, '["strength","core","low_impact","floor"]', '["none"]', NULL, '{"steps":["Lie on your back, arms extended overhead, legs straight.","Simultaneously lift your legs and torso toward each other — arms reach toward your toes, forming a ''V'' shape.","Lower back to the floor with control."],"cues":["💡 If you can''t keep legs straight, bend your knees — maintain quality over range.","Exhale sharply as you rise; inhale as you lower."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["hollow-body-hold","hanging-leg-raise","dead-bug"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_079', 'walking-lunge', 'Walking Lunge', 'cardio', '["quads","glutes","hamstrings","hip_flexors"]', NULL, '["cardio","low_impact","bodyweight","dynamic","loads_knee"]', '["none"]', NULL, '{"steps":["Stand tall with feet together. Step forward with your right foot into a lunge — front knee above ankle, rear knee toward the floor.","Without returning to start, step the rear foot forward to meet the front, then immediately lunge forward with the left foot.","Continue walking forward in this alternating pattern for the prescribed distance or reps."],"cues":["💡 Upright torso — resist leaning forward, even as you get tired.","Long steps challenge glutes and flexibility; shorter steps challenge quads more."]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["reverse-lunge","dumbbell-lunge","dumbbell-bulgarian-split-squat"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_052', 'wrist-flexor-stretch', 'Wrist Flexor Stretch', 'mobility', '["forearm_flexors","wrist"]', NULL, '["mobility","low_impact","no_floor","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Extend one arm in front, palm facing up. With the other hand, gently bend the fingers toward the floor.","Hold the stretch until you feel it along the inside of your forearm.","Switch to palm facing down (wrist extension stretch) for the opposing muscles. Repeat on both sides."],"cues":["💡 Essential for anyone who types, grips weights, or cycles — often skipped and later regretted.","Gentle pressure only — the wrist is a complex joint."]}', NULL, '{"supports":["time"],"base_duration_sec":30}', '{"substitutions":["forearm-wrist-stretch","wrist-ankle-circles"]}', 1, 1744700000000, 1744700000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex20_081', 'zone2-easy-run', 'Zone 2 Easy Run', 'cardio', '["cardiovascular_system","quads","hamstrings","calves","glutes"]', NULL, '["cardio","low_impact","zone2","conditioning","outdoor","loads_knee","loads_ankle"]', '["running_shoes","treadmill"]', NULL, '{"steps":["Set off at a fully conversational pace — you must be able to speak in full sentences throughout.","Maintain steady effort, not pace; if you feel out of breath, slow down.","Finish with a 2-minute walk to cool down."],"cues":["💡 Nasal breathing is a useful guide — if you need to open your mouth, you may be above Zone 2.","Zone 2 builds aerobic base and fat-burning capacity. Boring is the point."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', '{"substitutions":["easy-run-outdoor","treadmill-run-steady","brisk-walk"]}', 1, 1744700000000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_mil_cooper_test', '12-minute-cooper-test', '12-Minute Cooper Test', 'cardio', '["cardiovascular","quads","hamstrings","calves"]', NULL, '["cardio","outdoor","assessment","military","running"]', '["none"]', NULL, '{"steps":["Start a 12-minute timer on a measured track or GPS route","Run as far as possible in 12 minutes — pace yourself so you do not blow up in the first 3 minutes","Record the total distance covered when the timer ends"],"cues":["Even pacing beats going out fast and dying — aim for a pace you can hold for 10 minutes, then push the final 2","Your distance maps to your fitness level: < 2000 m = below baseline, 2400–2800 m = Cluster 1–3, > 2800 m = Cluster 4–6","💡 Use this as a benchmark every 4–6 weeks — not as a training session in itself"],"pregnancy_note":"Not appropriate during pregnancy. Consult your healthcare provider for a modified cardiovascular assessment."}', NULL, '{"supports":["time"],"base_duration_sec":720}', '{"substitutions":["zone-2-easy-run","running-intervals-outdoor"]}', 1, 1767830400000, 1777114247000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('1bb090ff-532b-5a98-b849-d170214b0f46', '90-90-stretch', '90-90 Stretch', 'mobility', '["hips","glutes"]', '["adductors"]', '["mobility","stretch","low_impact","quiet","floor"]', '["none"]', '["exercise_mat"]', '{"steps":["Sit with one leg in front bent ~90 degrees and the other to the side bent ~90 degrees.","Sit tall and gently lean into the front shin for external rotation.","Rotate toward back leg for internal rotation.","Move slowly and breathe."]}', NULL, '{"supports":["time"]}', '{"substitutions":["figure-4-stretch","pigeon-pose","hip-flexor-stretch"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('8d10d81c-af7c-5e5b-a855-5eb00134952d', 'air-squat', 'Air Squat', 'strength', '["quadriceps","glutes","hamstrings"]', '["core","calves"]', '["strength","bodyweight","lower_body","squat","no_floor","quiet","low_impact","loads_knee"]', '["none"]', '["none"]', '{"steps":["Stand with feet shoulder-width apart.","Sit hips back and down, keeping heels grounded.","Reach comfortable depth with neutral spine.","Stand up fully, squeezing glutes at the top."],"cues":["Knees track over toes.","Chest tall, brace core."]}', NULL, '{"supports":["reps","sets","tempo"]}', '{"substitutions":["goblet-squat","box-squat","sit-to-stand"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_back_squat', 'back-squat', 'Back Squat', 'strength', '["quads","hamstrings","glutes","erector_spinae"]', NULL, '["bodyweight","no_floor","high_impact","loads_knee","loads_lower_back","military"]', '["none"]', NULL, '{"steps":["Stand with feet shoulder-width apart; for a loaded version rest the bar across your upper traps","Push your hips back and descend, keeping your chest upright and core braced","Lower until your thighs are at least parallel to the floor","Drive through your full foot — heels and mid-foot — to stand"],"cues":["Knees track outward over your second toe throughout","Brace your core before every rep like you''re about to be punched in the stomach","💡 Bodyweight first: master the pattern before adding load. Heels rising = tight ankles — elevate slightly"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["squat","dumbbell-goblet-squat","front-squat"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_bicycle_crunch', 'bicycle-crunch', 'Bicycle Crunch', 'strength', '["obliques","rectus_abdominis","hip_flexors"]', NULL, '["bodyweight","floor","low_impact","core","military"]', '["none"]', NULL, '{"steps":["Lie on your back, hands loosely behind your head, elbows wide","Lift your shoulders off the floor and bring both knees to a 90° tabletop","Extend your right leg while rotating your right shoulder toward your left knee","Switch sides in a controlled cycling motion"],"cues":["Rotate from the ribs — don''t pull your neck with your hands","Keep both shoulders lifted throughout the movement","💡 Quality over speed — slow reps build more rotational strength"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dead-bug","standing-bicycle","v-up"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_bird_dog', 'bird-dog', 'Bird Dog', 'strength', '["core","lower_back","glutes"]', NULL, '["bodyweight","floor","low_impact","quiet"]', '["none"]', NULL, '{"steps":["On all fours, wrists under shoulders","Extend right arm and left leg simultaneously","Hold 2 seconds","Switch sides"],"cues":["Keep hips square","Move slowly and deliberately"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_body_scan', 'body-scan-meditation', 'Body Scan', 'recovery', '["full_body"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet","supine","recovery","pregnancy_safe","postnatal_safe"]', '["none"]', NULL, '{"steps":["Lie down comfortably","Close eyes","Slowly bring attention from feet up through body","Notice sensations without judgment"],"cues":["5-10 minutes ideal","Can be done in bed"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_box_breathing', 'box-breathing', 'Box Breathing', 'recovery', '["diaphragm"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Inhale for 4 counts","Hold for 4 counts","Exhale for 4 counts","Hold empty for 4 counts","Repeat 4-6 cycles"],"cues":["Used by elite athletes for stress control","Eyes closed if comfortable"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_box_step', 'box-step-up', 'Step Up', 'cardio', '["quadriceps","glutes","calves"]', NULL, '["bodyweight","no_floor","low_impact","loads_knee","loads_ankle"]', '["chair"]', NULL, '{"steps":["Stand in front of a stable chair, step, or bench that places your thigh at or near 90 degrees when your foot is on it. Place your entire right foot flat on the surface — heel included.","Drive through the right heel to step up, bringing your left knee up to hip height as you stand tall on the step. Avoid pushing off with the trail foot.","Stand tall at the top — fully extend the standing hip before lowering. Then lower your left foot slowly and with control back to the floor, followed by the right foot.","Complete all reps on the right side, then switch to the left, or alternate legs each rep."],"cues":["Push through the heel of the elevated foot — the glute of that leg should do the work, not a push-off from the floor foot.","Slow the descent — lowering with control builds more strength than a sloppy step-down.","💡 💡 Add dumbbells at your sides to progress once bodyweight feels easy. Increase the step height to increase the range of motion challenge."]}', NULL, '{"supports":["reps","time","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('36f46085-ae5b-5887-bb9a-201a8993a5cd', 'burpee', 'Burpee', 'cardio', '["full_body","legs","chest","core"]', '["shoulders"]', '["cardio","conditioning","full_body","high_impact","floor","loud","loads_knee","loads_ankle"]', '["none"]', '["none"]', '{"steps":["From standing, squat down and place hands on floor.","Jump (or step) feet back to a plank.","Optionally perform a push-up.","Jump (or step) feet forward and stand tall."],"cues":["Land softly.","Keep core braced in plank."]}', NULL, '{"supports":["reps","time","intervals"]}', '{"substitutions":["squat-thrust","step-back-burpee","mountain-climbers"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_calf_raise', 'calf-raise', 'Calf Raise', 'strength', '["calves"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand with feet hip-width","Rise onto toes","Hold 1 second","Lower slowly"],"cues":["Hold wall for balance if needed","Slow descent for more effect"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('95f1da8d-c126-5be3-8b1f-bb13139b44e9', 'cat-cow', 'Cat-Cow', 'mobility', '["spine"]', '["core"]', '["mobility","recovery","low_impact","quiet","floor"]', '["none"]', '["exercise_mat"]', '{"steps":["Start on all fours — hands under shoulders, knees under hips. Spine is neutral, no sag or arch.","Inhale: let your belly drop, lift your chest and tailbone gently toward the ceiling (cow position). Eyes look slightly forward.","Exhale: round your entire spine upward, tuck your chin to your chest and your tailbone under (cat position). Feel the stretch across your upper back."],"cues":["💡 Let your breath drive the movement — cow on the inhale, cat on the exhale. This links movement to your nervous system, not just your joints.","Move slowly and intentionally. This is mobility work, not a warm-up speed drill."]}', NULL, '{"supports":["time","reps"]}', '{"substitutions":["thread-the-needle","thoracic-rotation","pelvic-tilts"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('dadf0850-192a-52e2-8053-4b17da1584be', 'childs-pose', 'Child''s Pose', 'recovery', '["hips","back"]', '["shoulders"]', '["mobility","stretch","recovery","low_impact","quiet","floor"]', '["none"]', '["exercise_mat"]', '{"steps":["Kneel on a mat and sit your hips back toward your heels. Separate your knees as wide as comfortable or keep them together — both variations work.","Reach your arms forward along the floor and lower your forehead to the mat. Let your chest sink toward the ground.","Breathe slowly and deeply. With each exhale, allow your hips to settle a little further back and your spine to lengthen."],"cues":["Wider knees gives a deeper hip stretch and more space for your torso. Knees together emphasises the lower back stretch.","Breathe into your lower back — you should feel it expand laterally with each inhale. This is passive decompression.","💡 Use this as a reset between hard sets or as the final pose of any session. There is no wrong way to rest here."]}', NULL, '{"supports":["time"]}', '{"substitutions":["puppy-pose","supine-knees-to-chest","prayer-stretch"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_clean_pull', 'clean-pull', 'Clean Pull', 'strength', '["hamstrings","glutes","traps","upper_back","lats"]', NULL, '["strength","no_floor","high_impact","olympic","military"]', '["none"]', NULL, '{"steps":["Start standing, feet hip-width; hinge at the hips with a flat back to reach your hands to mid-shin height","Drive through your legs and extend your hips explosively — think of jumping straight up","As your hips fully extend, shrug your shoulders aggressively and pull your elbows high and wide","The bar (or your hands) rises to upper-chest height; lower under control and reset"],"cues":["Power comes from the legs and hips — the arms guide, not pull","Keep the bar (or hands) close to your body throughout","💡 This is the first pull of a clean — it builds the explosive hip extension needed for military physical tests"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["high-pull","dumbbell-upright-row","kettlebell-swing"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_counter_movement_jump', 'counter-movement-jump', 'Counter Movement Jump', 'strength', '["quads","hamstrings","glutes","calves"]', NULL, '["bodyweight","no_floor","high_impact","plyometric","assessment","loads_knee","loads_ankle","military"]', '["none"]', NULL, '{"steps":["Stand upright, feet shoulder-width, arms at your sides","Quickly dip into a quarter-squat while swinging your arms back","Immediately reverse — drive your arms up and extend your hips, knees, and ankles fully to jump as high as possible","Land softly, absorbing through ankles, knees, and hips","Reset fully before the next rep"],"cues":["The dip-and-drive is what makes this a counter-movement — use that elastic energy","Reach for the ceiling with your arms — it helps you jump higher","💡 Used in military and elite sports fitness testing. Focus on maximal height per jump, not speed"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["jump-squat","tuck-jump","broad-jump"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_dead_bug', 'dead-bug', 'Dead Bug', 'strength', '["core","transverse_abdominis"]', NULL, '["bodyweight","floor","low_impact","quiet","supine"]', '["none"]', NULL, '{"steps":["Lie on back, arms up, knees at 90°","Lower right arm and left leg towards floor","Return to start","Switch sides"],"cues":["Keep lower back pressed to floor","Move slowly"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_diamond_pushup', 'diamond-push-up', 'Diamond Push-up', 'strength', '["triceps","chest","shoulders"]', NULL, '["bodyweight","floor","high_impact","loads_shoulder"]', '["none"]', NULL, '{"steps":["Start in a push-up position with your hands close together directly beneath your chest — thumbs and index fingers touching to form a diamond or triangle shape.","Brace your core and lower your chest toward your hands, keeping your elbows tucked close to your sides. They should brush your ribs on the way down, not flare out.","Press back up to full arm extension, squeezing your triceps hard at the top.","Maintain a rigid plank throughout — hips level, no sagging at the waist or piking at the hips."],"cues":["Triceps do most of the work here — think of this as a tricep exercise that also loads the chest.","Elbows stay close to your ribs throughout — if they flare wide, you lose the tricep emphasis entirely.","💡 💡 Beginner: elevate hands on a chair to reduce load. Advanced: use a 3-second controlled descent for maximum time under tension."]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_downward_dog', 'downward-dog', 'Downward Dog', 'mobility', '["hamstrings","calves","shoulders","spine"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["From all fours, tuck toes, push hips up and back","Form inverted V shape","Press heels toward floor","Alternate bending each knee (pedalling)"],"cues":["Spread fingers wide","Relax head between arms"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_db_curl', 'dumbbell-bicep-curl', 'Dumbbell Bicep Curl', 'strength', '["biceps","forearms"]', NULL, '["dumbbell","no_floor","low_impact","no_sweat","quiet"]', '["dumbbell"]', NULL, '{"steps":["Stand or sit, dumbbells at sides, palms forward","Curl weights to shoulders","Squeeze at top","Lower slowly"],"cues":["Keep elbows fixed at sides","Full range of motion"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_db_deadlift', 'dumbbell-deadlift', 'Dumbbell Deadlift', 'strength', '["hamstrings","glutes","lower_back"]', NULL, '["dumbbell","no_floor","loads_lower_back"]', '["dumbbell"]', NULL, '{"steps":["Stand, dumbbells in front of thighs","Hinge at hips, sending them back","Lower weights along legs to mid-shin","Drive hips forward to return"],"cues":["Flat back throughout","Squeeze glutes at top"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('0ba3d7b5-17a9-562c-a74c-e31b90692dbc', 'dumbbell-floor-press', 'Dumbbell Floor Press', 'strength', '["chest","triceps","shoulders"]', '["core"]', '["strength","dumbbell","upper_body","push","floor","quiet","low_impact","supine","loads_shoulder"]', '["dumbbell"]', '["exercise_mat","bench"]', '{"steps":["Lie on your back with knees bent, feet flat on the floor. Hold a dumbbell in each hand directly over your chest, arms extended, palms facing your feet.","Bend your elbows and lower the dumbbells in a controlled arc until your upper arms lightly contact the floor. Keep elbows at roughly 45 degrees from your torso — not straight out to your sides.","Without bouncing, press back up from the floor contact point. Exhale on the press. Squeeze your chest at the top.","The floor acts as a built-in range-of-motion limit — it protects your shoulder by preventing overstretching at the bottom."],"cues":["Wrists stay stacked over elbows throughout — wrists bending backward is a form break and injury risk.","Never bounce off the floor — the pause and press from a dead stop is what makes this version effective.","💡 💡 The shorter range of motion compared to bench press means you can often handle more volume safely. Excellent for building the upper chest."]}', NULL, '{"supports":["weight","reps","sets","tempo"]}', '{"substitutions":["push-up","bench-press","incline-push-up"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_db_lateral_raise', 'dumbbell-lateral-raise', 'Dumbbell Lateral Raise', 'strength', '["shoulders","traps"]', NULL, '["dumbbell","no_floor","low_impact","no_sweat","quiet","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Stand with feet hip-width holding a dumbbell in each hand at your sides. Raise both dumbbells out to the sides until your arms are parallel to the floor, leading with your elbows slightly.","Hold briefly at the top — do not let momentum carry the weight. Your palms should face down at the top.","Lower slowly — 3 seconds down. The eccentric builds the rear and lateral deltoid far more than the lift up."],"cues":["💡 Lighter than you think — lateral raises with heavy weight turn into a trap shrug. Use a weight you can control fully.","Slight forward lean (10–15 degrees) shifts more load onto the lateral deltoid and less onto the trap."]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('3b258049-88d8-5596-8aa3-41d49a3cbef4', 'dumbbell-row', 'Dumbbell Row', 'strength', '["lats","upper_back","biceps"]', '["rear_delts","core"]', '["strength","dumbbell","upper_body","pull","no_floor","quiet","low_impact","loads_lower_back"]', '["dumbbell"]', '["bench"]', '{"steps":["Stand with feet hip-width, hinge forward 45° keeping your back flat. Hold a dumbbell in each hand, arms hanging straight down.","Drive your elbows back toward your hips, pulling the dumbbells to your lower ribcage. Squeeze your shoulder blades together at the top.","Lower with control — resist the weight pulling your shoulders forward."],"cues":["💡 Hinge first, row second — set the flat back before you pull anything.","Think elbows to back pockets, not hands to chest. The elbow leads the movement."]}', NULL, '{"supports":["weight","reps","sets","tempo"]}', '{"substitutions":["band-row","inverted-row","one-arm-cable-row"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_db_shoulder_press', 'dumbbell-shoulder-press', 'Dumbbell Shoulder Press', 'strength', '["shoulders","triceps"]', NULL, '["dumbbell","no_floor","low_impact","loads_shoulder"]', '["dumbbell"]', NULL, '{"steps":["Sit or stand with dumbbells at shoulder height, palms facing forward. Elbows should be at roughly 90 degrees and just below the level of your ears — not dropped too low or flared too high.","Press both dumbbells straight overhead until your arms are fully extended. Exhale on the way up. Do not lock out your elbows hard at the top.","Lower slowly and with control back to the starting position, elbows returning to 90 degrees. Inhale on the way down.","Keep your core firmly braced throughout — avoid arching your lower back as the weight goes overhead."],"cues":["Wrists stay stacked over elbows throughout — wrists bending backward increases injury risk and reduces power transfer.","If you feel pinching at the front of the shoulder, try a neutral grip (palms facing each other) — this externally rotates the shoulder into a safer position.","💡 💡 Seated removes the option to use leg drive, making it a purer shoulder challenge. Standing adds full-body stability demand."]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_db_tricep_kickback', 'dumbbell-tricep-kickback', 'Dumbbell Tricep Kickback', 'strength', '["triceps"]', NULL, '["dumbbell","no_floor","low_impact","no_sweat","quiet"]', '["dumbbell"]', NULL, '{"steps":["Hinge forward 45°, upper arm parallel to floor","Extend forearm back until arm is straight","Squeeze tricep","Return slowly"],"cues":["Keep upper arm still","Full extension"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_flutter_kicks', 'flutter-kicks', 'Flutter Kicks', 'strength', '["hip_flexors","rectus_abdominis","lower_abs"]', NULL, '["bodyweight","floor","low_impact","core","military"]', '["none"]', NULL, '{"steps":["Lie on your back, hands palms-down under your lower back for support","Lift both legs to roughly 30–45° off the floor — legs straight","Alternately kick one leg up and the other down in small, rapid movements","Maintain continuous motion throughout the set"],"cues":["Lower back stays pressed into your hands — don''t arch","Keep your head and shoulders relaxed on the floor","💡 Raise the legs higher to make it easier; lower to make it harder"]}', NULL, '{"supports":["time","sets"]}', '{"substitutions":["dead-bug","heel-slides","hollow-body-hold"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('45fca5b0-545a-5ce0-a9fc-c245998d81fa', 'forward-lunge', 'Forward Lunge', 'strength', '["quadriceps","glutes","hamstrings"]', '["calves","core"]', '["strength","bodyweight","lower_body","unilateral","balance","no_floor","quiet","low_impact","loads_knee"]', '["none"]', '["none"]', '{"steps":["Stand tall, step forward into a long stride.","Lower until front thigh is near parallel and rear knee approaches the floor.","Drive through front heel to return to start.","Repeat other side."],"cues":["Torso upright.","Front knee tracks over mid-foot."]}', NULL, '{"supports":["reps","sets","time"]}', '{"substitutions":["reverse-lunge","split-squat","step-up"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_front_squat', 'front-squat', 'Front Squat', 'strength', '["quads","glutes","core","upper_back"]', NULL, '["bodyweight","no_floor","high_impact","military"]', '["none"]', NULL, '{"steps":["Stand with feet shoulder-width; hold your arms crossed in front of your chest (or in clean-rack position if using a bar)","Keeping your elbows high and torso upright, push your hips back and squat","Descend until thighs are parallel — the front-loaded position demands a more upright torso than a back squat","Drive through your heels to stand, maintaining elbow height throughout"],"cues":["Elbows dropping = weight falls forward and form breaks. Practise with a light dumbbell held at your chest","More quad-dominant than back squat — great for military preparation","💡 If your wrists ache in rack position, use the crossed-arm variation"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["back-squat","squat","dumbbell-goblet-squat"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_hip_circles', 'gentle-hip-circles', 'Gentle Hip Circles', 'recovery', '["hips","lower_back"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Stand feet shoulder-width, hands on hips","Make large circles with hips clockwise x10","Reverse direction x10"],"cues":["Move slowly","Great after sitting long periods"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('6009a4e3-4c30-5903-9a81-745ac253d38a', 'glute-bridge', 'Glute Bridge', 'strength', '["glutes","hamstrings","core"]', '["lower_back"]', '["strength","bodyweight","posterior_chain","floor","quiet","low_impact","supine","postnatal_safe"]', '["none"]', '["exercise_mat"]', '{"steps":["Lie on back with knees bent and feet flat.","Brace core and tuck pelvis slightly.","Drive through heels to lift hips.","Pause, squeeze glutes, then lower with control."],"cues":["Avoid over-arching the low back.","Knees stay in line with toes."]}', NULL, '{"supports":["reps","sets","tempo","time_under_tension"]}', '{"substitutions":["hip-thrust","single-leg-glute-bridge","good-morning"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('2b9f9857-49f2-5fbb-b30d-d8eb02bd31b5', 'goblet-squat', 'Goblet Squat', 'strength', '["quadriceps","glutes","hamstrings","core"]', '["upper_back"]', '["strength","dumbbell","lower_body","squat","no_floor","quiet","low_impact","loads_knee"]', '["dumbbell"]', '["exercise_mat"]', '{"steps":["Hold a dumbbell vertically at chest height, both hands cupping the top end, elbows pointing down. Stand with feet shoulder-width apart, toes turned out 15-30 degrees.","Take a breath in. Push your hips back and bend your knees, lowering until your thighs reach parallel to the floor or deeper. Keep the dumbbell close to your chest throughout.","At the bottom, your elbows can press lightly against the inside of your knees — this helps keep them tracking outward over your toes.","Drive through your heels to stand. Squeeze your glutes firmly at the top and exhale. Repeat."],"cues":["The weight in front naturally counterbalances you — use it to sit into a deeper position than a regular squat.","Chest stays tall the entire way down and up. The moment the dumbbell pulls you forward, go lighter.","💡 💡 Beginner: squat only as deep as you can with a flat back. Advanced: pause 2 seconds at the bottom before driving up."]}', NULL, '{"supports":["weight","reps","sets","tempo"]}', '{"substitutions":["air-squat","front-squat","box-squat"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_hand_release_pushup', 'hand-release-push-up', 'Hand Release Push-Up', 'strength', '["chest","triceps","anterior_deltoid","core","upper_back"]', NULL, '["bodyweight","floor","high_impact","push","military"]', '["none"]', NULL, '{"steps":["Lower yourself fully to the floor in a push-up — chest and thighs touching the ground","Lift both hands briefly off the floor, keeping elbows slightly tucked","Replace your hands and press explosively back up to full arm extension","Reset and repeat — each rep starts with a full stop at the floor"],"cues":["The ground contact forces a full range of motion — no half-reps","Squeeze shoulder blades together when you lift your hands","💡 This is the standard Dutch military fitness test push-up — form counts"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["push-up","incline-push-up","knee-push-up"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('dace5250-7566-5a2d-bdf4-ee8763e94f79', 'high-knees', 'High Knees', 'cardio', '["hip_flexors","quadriceps","calves","core"]', '["glutes"]', '["cardio","conditioning","no_floor","high_impact","loud","loads_ankle"]', '["none"]', '["running_shoes"]', '{"steps":["Run in place lifting knees toward hip height.","Pump arms naturally.","Maintain tall posture and quick cadence."],"cues":["Land softly under hips.","Keep core braced."]}', NULL, '{"supports":["time","intervals","cadence"]}', '{"substitutions":["marching-high-knees","step-ups","jump-rope"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_high_pull', 'high-pull', 'High Pull', 'strength', '["traps","deltoids","biceps","upper_back","hamstrings"]', NULL, '["strength","no_floor","high_impact","military"]', '["dumbbell"]', NULL, '{"steps":["Stand with feet hip-width, holding a dumbbell or barbell with an overhand grip at thigh height","Initiate with a slight knee bend, then drive hips forward and shrug your shoulders hard","As momentum carries the weight up, pull your elbows high and wide — bar reaches chin height","Lower under control back to thigh height and repeat"],"cues":["This is a power movement — drive from the lower body, don''t muscle it up with your arms","Elbows stay above wrists throughout the pull","💡 Simpler than a clean pull — great entry point to Olympic-style lifting"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["clean-pull","dumbbell-upright-row","dumbbell-shrug"]}', 1, 1767830400000, 1777744522000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_hip_flexor_stretch', 'hip-flexor-stretch', 'Hip Flexor Stretch', 'mobility', '["hip_flexors","quadriceps"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Step right foot forward into lunge","Lower left knee toward floor (or keep standing)","Shift weight forward until you feel stretch in left hip","Hold, switch sides"],"cues":["Tall spine","Squeeze back glute for deeper stretch"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_incline_pushup', 'incline-push-up', 'Incline Push-up', 'strength', '["chest","triceps","shoulders"]', NULL, '["bodyweight","no_floor","low_impact","loads_shoulder"]', '["chair"]', NULL, '{"steps":["Hands on edge of chair or bench","Body straight from head to heels","Lower chest to surface","Push back up"],"cues":["Easier than floor push-up","Great for beginners"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('76366f52-09c2-585f-9ffe-12cab60a388e', 'jumping-jacks', 'Jumping Jacks', 'cardio', '["full_body","calves","shoulders"]', '["core"]', '["cardio","conditioning","no_floor","high_impact","loud","loads_knee","loads_ankle"]', '["none"]', '["running_shoes"]', '{"steps":["Stand tall with feet together and hands at sides.","Jump feet out as arms sweep overhead.","Jump back to start, repeat rhythmically."],"cues":["Land softly.","Keep breathing steady."]}', NULL, '{"supports":["time","intervals"]}', '{"substitutions":["step-jacks","marching-in-place","high-knees"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_lunge', 'lunge', 'Lunge', 'strength', '["quads","hamstrings","glutes"]', NULL, '["bodyweight","no_floor","high_impact","unilateral","loads_knee","military"]', '["none"]', NULL, '{"steps":["Stand with feet together, hands on hips or at sides","Step one foot forward roughly 60–70 cm, planting it flat","Lower your back knee toward the floor, front thigh nearly parallel","Push through your front heel to step back to the start position","Alternate legs each rep"],"cues":["Keep your torso upright — don''t lean forward","Front knee stays above your ankle, not over your toes","💡 For balance difficulty: hold onto a wall. To progress: add load or go walking lunge"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["reverse-lunge","walking-lunge","lateral-lunge"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_march_in_place', 'march-in-place', 'March in Place', 'cardio', '["legs","core"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Stand tall","Alternate lifting knees to hip height","Swing opposite arm","Keep steady rhythm"],"cues":["Great warm-up or low-impact cardio","No jumping required"]}', NULL, '{"supports":["time","reps"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_mountain_climber', 'mountain-climber', 'Mountain Climber', 'mixed', '["core","hip_flexors","anterior_deltoid","quads"]', NULL, '["bodyweight","floor","high_impact","cardio","core","loads_shoulder","military"]', '["none"]', NULL, '{"steps":["Start in a high plank position — hands under shoulders, body straight","Drive your right knee toward your chest, then quickly switch — right leg back, left knee forward","Alternate legs in a running motion, keeping your hips level","Keep a steady rhythm throughout"],"cues":["Hips stay flat — don''t bounce them up with each drive","The faster the pace, the more cardiovascular the demand","💡 Slow = core strength focus. Fast = conditioning. Start slow to nail the form"]}', NULL, '{"supports":["reps","sets","time"]}', '{"substitutions":["plank","dead-bug","bird-dog"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('1cd70ca6-6293-5da7-92f0-9504c7e55e58', 'mountain-climbers', 'Mountain Climbers', 'cardio', '["core","shoulders","hip_flexors"]', '["chest"]', '["cardio","conditioning","floor","medium_impact","moderate_noise","loads_shoulder"]', '["none"]', '["exercise_mat"]', '{"steps":["Start in a high plank with hands under shoulders.","Drive one knee toward chest, then switch quickly.","Keep hips level and spine neutral."],"cues":["Shoulders stacked over wrists.","Avoid bouncing hips."]}', NULL, '{"supports":["time","intervals","reps"]}', '{"substitutions":["slow-mountain-climbers","bear-plank-knee-taps","high-knees"]}', 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_neck_stretch', 'neck-stretch', 'Neck Stretch', 'mobility', '["neck","traps"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Sit or stand tall","Tilt right ear to right shoulder, hold 20s","Tilt left ear to left shoulder, hold 20s","Drop chin to chest, hold 20s"],"cues":["No rotation — only lateral tilt","Gentle pressure only"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_pigeon_pose', 'pigeon-pose', 'Pigeon Pose', 'mobility', '["hip_flexors","glutes","piriformis"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["From all fours, bring right knee behind right wrist","Extend left leg behind","Sink hips toward floor","Hold, switch sides"],"cues":["Use folded blanket under hip if tight","Breathe deeply"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('f07deff3-a86b-51e0-93cf-2c20d2338938', 'plank', 'Plank', 'strength', '["core","shoulders","glutes"]', '["upper_back"]', '["core","bodyweight","isometric","floor","quiet","low_impact","loads_shoulder","military"]', '["none"]', '["exercise_mat"]', '{"steps":["Place forearms on the floor with elbows under shoulders.","Extend legs back and tuck pelvis slightly.","Hold a straight line head-to-heel.","Breathe slowly while maintaining tension."],"cues":["Ribs down.","Glutes tight.","Avoid sagging hips."]}', NULL, '{"supports":["time"]}', '{"substitutions":["side-plank","dead-bug","bird-dog"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_plyometric_pushup', 'plyometric-push-up', 'Plyometric Push-Up', 'strength', '["chest","triceps","anterior_deltoid","core"]', NULL, '["bodyweight","floor","high_impact","push","plyometric","loads_shoulder","military"]', '["none"]', NULL, '{"steps":["Start in a standard push-up position — hands shoulder-width, body straight","Lower your chest to the floor with control","Drive up explosively so your hands leave the floor briefly at the top","Land with soft elbows and immediately lower into the next rep"],"cues":["Generate power from your chest — don''t push with wrists only","Land as softly as possible to protect your wrists and elbows","💡 Builds explosive upper body power — foundational for military fitness"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["push-up","hand-release-push-up","incline-push-up"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_pmr', 'progressive-muscle-relaxation', 'Progressive Muscle Relaxation', 'recovery', '["full_body"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Lie down or sit comfortably with eyes closed. Start at your feet: curl your toes tight for 5 seconds, then release completely. Notice the difference.","Work systematically upward — calves, thighs, glutes, abdomen, hands, forearms, shoulders, face. Tense each area for 5 seconds, then let go fully.","After the final release, lie still for 60 seconds. Breathe naturally and observe the heaviness in your body."],"cues":["💡 The contrast between tension and release is the mechanism — your nervous system learns what genuine relaxation feels like, then can reproduce it.","If your mind wanders, guide it back with the question: what is the least tense part of my body right now?"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('1c0ead14-ec38-5e21-b359-3ed936a0c7ac', 'push-up', 'Push-up', 'strength', '["chest","triceps","shoulders","core"]', '["serratus_anterior"]', '["strength","bodyweight","upper_body","push","floor","classic","quiet","low_impact","loads_shoulder","military"]', '["none"]', '["exercise_mat"]', '{"steps":["Start in a high plank with hands under shoulders.","Brace core and keep body in a straight line.","Lower chest toward the floor with control.","Press back up to full lockout without shrugging."],"cues":["Ribs down, glutes tight.","Elbows ~30-45 degrees from torso.","Neck neutral."]}', NULL, '{"supports":["reps","sets","tempo","time_under_tension"]}', '{"substitutions":["incline-push-up","knee-push-up","dumbbell-floor-press"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_reverse_lunge', 'reverse-lunge', 'Reverse Lunge', 'strength', '["quadriceps","glutes","hamstrings"]', NULL, '["bodyweight","no_floor","low_impact","loads_knee"]', '["none"]', NULL, '{"steps":["Stand tall, feet hip-width","Step back with right foot","Lower back knee toward floor","Push through front heel to return"],"cues":["Keep front knee over ankle","Stay upright"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_scissor_jump', 'scissor-jump', 'Scissor Jump', 'strength', '["quads","hamstrings","glutes","calves"]', NULL, '["bodyweight","floor","high_impact","plyometric","loads_knee","military"]', '["none"]', NULL, '{"steps":["Start in a lunge position — right foot forward, left foot back, both knees bent","Drive through both feet to jump explosively off the floor","While airborne, switch your feet so your left foot lands forward","Absorb the landing by bending both knees, immediately drop into the lunge and repeat"],"cues":["Soft landing — heel-to-toe, knees tracking over toes","Arms swing opposite to your legs for balance","💡 Impact is high — reduce height if your joints protest. Beginner: do slow alternating lunges"]}', NULL, '{"supports":["time","sets","reps"]}', '{"substitutions":["lunge","reverse-lunge","jump-squat"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_seated_twist', 'seated-spinal-twist', 'Seated Spinal Twist', 'mobility', '["spine","obliques","hips"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Sit cross-legged or legs extended","Place right hand behind you, left on right knee","Twist right on exhale","Hold, switch sides"],"cues":["Lengthen spine on inhale","Deepen twist on exhale"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_shadow_boxing', 'shadow-boxing', 'Shadow Boxing', 'cardio', '["shoulders","core","arms"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat"]', '["none"]', NULL, '{"steps":["Stance: feet shoulder-width, slight bend in knees","Throw jab-cross combinations","Add hooks and uppercuts","Move feet between combinations"],"cues":["Stays in one spot","Good stress relief"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_shoulder_roll', 'shoulder-roll-stretch', 'Shoulder Rolls', 'mobility', '["shoulders","traps","neck"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Stand or sit tall. Roll both shoulders forward in large, slow circles — feel the full range at the top and back of each circle. Complete 10 reps forward.","Reverse: roll both shoulders backward in the same large circles. Focus on pulling the shoulder blades together and down at the back of each circle.","Finish with a chest stretch: clasp your hands behind your back, squeeze your shoulder blades together, and lift your hands gently. Hold for 20 seconds."],"cues":["💡 Most people only roll the tops of their shoulders. Exaggerate the backward phase — pulling blades back and down is where desk-worker tension lives.","Slow down. Shoulder rolls done quickly produce zero mobility benefit."]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_single_leg_deadlift', 'single-leg-deadlift', 'Single-Leg Deadlift', 'strength', '["hamstrings","glutes","core"]', NULL, '["bodyweight","no_floor","balance","unilateral","military"]', '["none"]', NULL, '{"steps":["Stand on your right foot, slight bend in the knee, left foot just off the floor","Hinge forward at the hip, sending your left leg straight back as a counterbalance — your body forms a T","Reach your hands toward the floor (or hold a dumbbell in your right hand)","Squeeze your right glute to drive back to standing; complete all reps on one side before switching"],"cues":["Move as one unit — your torso and back leg travel together like a seesaw","Keep your hips square to the floor — don''t let the floating hip open out","💡 Wobbling is normal at first. Find a fixed spot to stare at for balance"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["dumbbell-single-leg-romanian-deadlift","bird-dog","good-morning"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_skater_hop', 'skater-hop', 'Skater Hop', 'cardio', '["glutes","quadriceps","calves"]', NULL, '["bodyweight","no_floor","high_impact","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Jump laterally to the right, landing on right foot","Swing left leg behind","Jump left, landing on left foot","Repeat with rhythm"],"cues":["Keep chest up","Land softly"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_squat', 'squat', 'Squat', 'strength', '["quads","hamstrings","glutes"]', NULL, '["bodyweight","no_floor","high_impact","military"]', '["none"]', NULL, '{"steps":["Stand with feet shoulder-width apart, toes turned out slightly","Push your hips back and bend your knees, lowering until thighs are parallel to the floor","Keep your chest up and knees tracking over your toes throughout","Drive through your heels to stand back up"],"cues":["Weight stays on mid-foot to heel — don''t let heels rise","Knees stay in line with your second toe","💡 Beginner: squat to a chair height. Advanced: add a pause at the bottom"]}', NULL, '{"supports":["reps","sets"]}', '{"substitutions":["jump-squat","sumo-squat","supported-wall-squat"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_forward_fold', 'standing-forward-fold', 'Standing Forward Fold', 'mobility', '["hamstrings","lower_back","calves"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Stand, feet hip-width","Hinge forward from hips","Let arms hang or grab elbows","Hold, breathe into the stretch"],"cues":["Bend knees if needed","Relax neck completely"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_quad_stretch', 'standing-quad-stretch', 'Standing Quad Stretch', 'mobility', '["quadriceps","hip_flexors"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Stand on one leg — rest your free hand on a wall, chair back, or doorframe for balance. Shift your weight solidly onto the supporting foot.","Bend your other knee and bring your heel toward your glute. Reach back with the same-side hand and hold your ankle — not your foot. If your hand cannot reach, use a strap or towel.","Gently pull your heel closer to your glutes while pressing your hip forward slightly on the stretching side. Your stretching knee should point straight down, not drift outward.","Hold 20-30 seconds with steady breathing, then slowly release and switch sides. Never force the range — let the stretch come to you."],"cues":["Knees together is the key cue — the stretch is significantly reduced if the bent knee drifts wide of the standing leg.","Stand tall with both hips level — hiking one hip ruins the quad alignment and reduces the stretch.","Pressing the stretching hip slightly forward adds a hip flexor component — valuable for anyone who sits for long periods."]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_step_touch', 'step-touch', 'Step Touch', 'cardio', '["legs","glutes"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Step right foot to the right","Bring left foot to meet it","Step left, bring right to meet","Add arm swing for intensity"],"cues":["Silent — great for no_clothing days","Comfortable pace"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_superman', 'superman-hold', 'Superman Hold', 'strength', '["lower_back","glutes","hamstrings"]', NULL, '["bodyweight","floor","low_impact","prone","loads_lower_back"]', '["none"]', NULL, '{"steps":["Lie face down, arms extended overhead","Lift arms, chest, and legs off floor simultaneously","Hold 2 seconds","Lower slowly"],"cues":["Keep neck neutral","Squeeze glutes at top"]}', NULL, '{"supports":["reps","sets","time"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_thread_needle', 'thread-the-needle', 'Thread the Needle', 'mobility', '["thoracic_spine","shoulders","neck"]', NULL, '["bodyweight","floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["On all fours","Slide right arm under left arm along floor","Rest right shoulder and cheek on floor","Hold, switch sides"],"cues":["Keep hips high","Great for upper back tension"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_tricep_dip', 'tricep-chair-dip', 'Tricep Chair Dip', 'strength', '["triceps","shoulders"]', NULL, '["bodyweight","no_floor","low_impact"]', '["chair"]', NULL, '{"steps":["Sit on edge of chair, hands gripping edge","Slide off, arms straight","Bend elbows to 90°","Push back up"],"cues":["Keep back close to chair","Don''t shrug shoulders"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_wall_pushup', 'wall-push-up', 'Wall Push-up', 'strength', '["chest","triceps","shoulders"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","loads_shoulder"]', '["none"]', NULL, '{"steps":["Stand arm-length from wall","Place palms flat, shoulder-width","Lower chest to wall, elbows at 45°","Push back to start"],"cues":["Keep body straight","Breathe out on push"]}', NULL, '{"supports":["reps","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_wall_sit', 'wall-sit', 'Wall Sit', 'strength', '["quadriceps","glutes"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet","loads_knee"]', '["none"]', NULL, '{"steps":["Stand with your back flat against a smooth wall, feet roughly 60 cm out from the wall and shoulder-width apart, toes pointing forward.","Slide down the wall until your thighs are parallel to the floor and your knees form a 90-degree angle. Both your lower and upper back should stay in contact with the wall.","Press your heels into the floor and breathe steadily. Keep your arms relaxed at your sides or resting on your thighs — no pushing off with your hands.","When your knees creep above 90° or you lose contact with the wall, the set is done. Step up from the position rather than sliding further."],"cues":["Weight in your heels — you should be able to wiggle your toes without shifting forward.","Quads burning is normal and expected. Stop if you feel sharp pain in your knees, not just burn in your muscles.","💡 💡 Intermediate: hold dumbbells across your thighs to increase load. Advanced: add a slow calf raise hold while maintaining position."]}', NULL, '{"supports":["time","sets"]}', NULL, 1, 1767830400000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_warrior_i', 'warrior-i-pose', 'Warrior I', 'mobility', '["quadriceps","hip_flexors","shoulders"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Step right foot forward, left foot back at 45°","Bend front knee to 90°","Raise both arms overhead","Hold, switch sides"],"cues":["Square hips to front","Strong back leg"]}', NULL, '{"supports":["time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_mil_weighted_march', 'weighted-march', 'Weighted March', 'cardio', '["quads","hamstrings","glutes","calves","core","upper_back"]', NULL, '["cardio","outdoor","military","weighted","low_impact","loads_lower_back"]', '["none"]', NULL, '{"steps":["Load your rucksack or vest to the prescribed weight; adjust straps so the pack sits high and snug","Set your pace: 5.5 km/h (military standard) or 6 km/h (advanced)","March with upright posture — chest up, shoulders back, core braced throughout","Swing your arms naturally; short, quick steps are more efficient than long strides","Monitor your pace with a GPS watch or app; stay within ±0.3 km/h of target speed"],"cues":["The load accumulates — what feels easy at minute 5 feels heavy at minute 20","Heel-to-toe foot strike at march pace — don''t shuffle","💡 Beginner (0 kg): focus on pace and posture. Progress: +5–10 kg every 2 weeks","💡 Intermediate (25 kg): standard Defensie preparation load","💡 Advanced (35–45 kg): matches Cluster 4–6 Opleiding targets"]}', NULL, '{"supports":["time","sets"]}', '{"substitutions":["brisk-walking","treadmill-run"]}', 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('ex_wrist_circles', 'wrist-ankle-circles', 'Wrist & Ankle Circles', 'recovery', '["wrists","ankles","forearms"]', NULL, '["bodyweight","no_floor","low_impact","no_sweat","quiet"]', '["none"]', NULL, '{"steps":["Extend arms, rotate wrists in circles x10 each direction","Lift one foot, rotate ankle x10 each direction","Switch feet"],"cues":["Good office break movement","Increases joint fluid circulation"]}', NULL, '{"supports":["reps","time"]}', NULL, 1, 1767830400000, 1767830400000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000001-run0-4000-8000-run000000001', 'run-interval-level-1', 'Run/Walk — Gentle Start', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run gently at an easy, controlled effort — think of it as a purposeful shuffle, not a sprint.","When the rest timer starts, walk briskly. Keep moving and breathe steadily.","Repeat for all rounds. If you need to stop early, that is your body giving you the right signal."],"cues":["💡 Effort target: 70–80% max — HR should reach 140–155 bpm during each run","💡 Pace guide: 6:00–8:30 min/km (7–10 km/h). On a treadmill: 7.5 km/h is a good start","💡 Walk recovery is not optional — full recovery between efforts is what makes HIIT work","💡 This is polarised training: the run is hard, the walk is truly easy"]}', NULL, '{"supports":["time"],"base_duration_sec":30,"custom_rest_sec":90,"fixed_sets":6,"run_level":1}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000002-run0-4000-8000-run000000002', 'run-interval-level-2', 'Run/Walk — 1 Min Intervals', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run at a strong, controlled effort — not a sprint, but clearly working hard.","Walk steadily when the rest timer starts. Do not stop — keep your legs moving.","Complete all rounds. Equal time running and walking."],"cues":["💡 Effort target: 80–85% max — HR should reach 155–165 bpm during each interval","💡 Pace guide: 5:30–7:30 min/km (8–11 km/h). Treadmill: 9–10 km/h effort, 5 km/h walk","💡 Midfoot landing reduces joint stress — avoid landing heel-first","💡 If your breathing stops you from speaking at all, reduce pace by 0.5 km/h"]}', NULL, '{"supports":["time"],"base_duration_sec":60,"custom_rest_sec":60,"fixed_sets":6,"run_level":2}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000003-run0-4000-8000-run000000003', 'run-interval-level-3', 'Run/Walk — Build 1', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run at a hard, sustained effort — your breathing should be clearly laboured.","Walk when the rest timer begins. Breathe deep and settle your heart rate below 130 bpm.","Complete all rounds. Consistency over speed — every round at the same effort."],"cues":["💡 Effort target: 82–87% max — HR target 158–168 bpm during effort","💡 Pace guide: 5:00–7:00 min/km (8.5–12 km/h). Treadmill: 10 km/h effort, 5.5 km/h walk","💡 Relax your shoulders and hands — tension costs energy","💡 Recovery walk: HR should drop below 130 before the next effort starts"]}', NULL, '{"supports":["time"],"base_duration_sec":90,"custom_rest_sec":60,"fixed_sets":6,"run_level":3}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000004-run0-4000-8000-run000000004', 'run-interval-level-4', 'Run/Walk — Build 2', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run at a strong, sustainable pace — hard enough that speech requires effort.","Walk when the rest timer starts. Drop your heart rate actively — breathe deep.","Complete all rounds. You are building real aerobic power now."],"cues":["💡 Effort target: 85–88% max — HR target 162–170 bpm during effort","💡 Pace guide: 5:00–6:30 min/km (9–12 km/h). Treadmill: 10–11 km/h effort, 5.5 km/h walk","💡 Short stride, quick turnover beats long slow strides for HIIT efficiency","💡 Hips forward, body upright — not hunched. Posture holds your pace."]}', NULL, '{"supports":["time"],"base_duration_sec":120,"custom_rest_sec":60,"fixed_sets":5,"run_level":4}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000005-run0-4000-8000-run000000005', 'run-interval-level-5', 'Run/Walk — Tempo Build', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run at a pace that challenges your breathing — speaking takes real effort but one word is possible.","Walk when the rest timer starts. Heart rate should drop noticeably — aim for below 130.","Complete all rounds. You are building serious HIIT fitness."],"cues":["💡 Effort target: 87–90% max — HR target 165–175 bpm during effort","💡 Pace guide: 4:45–6:00 min/km (10–12.5 km/h). Treadmill: 11 km/h effort, 6 km/h walk","💡 Drive your arms forward — arm drive sets the rhythm for your legs","💡 Perceived effort: 8–9 out of 10. If it does not feel hard, push the pace."]}', NULL, '{"supports":["time"],"base_duration_sec":180,"custom_rest_sec":60,"fixed_sets":5,"run_level":5}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000006-run0-4000-8000-run000000006', 'run-interval-level-6', 'Run/Walk — Extended Intervals', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","run_interval","running","no_floor","hiit","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Run at a strong, controlled pace. You are approaching lactate threshold — this should feel genuinely demanding.","Walk when the rest timer starts — use it actively to prepare for the next effort.","Complete all rounds. At this level the walks are strategic recovery, not a break."],"cues":["💡 Effort target: 88–92% max — HR target 168–178 bpm during effort","💡 Pace guide: 4:30–5:30 min/km (11–13 km/h). Treadmill: 11.5–12.5 km/h effort, 6 km/h walk","💡 5-minute efforts at this intensity build lactate threshold — this is where real fitness is made","💡 Keep form sharp even when tired — fatigue is when injury risk is highest"]}', NULL, '{"supports":["time"],"base_duration_sec":300,"custom_rest_sec":60,"fixed_sets":4,"run_level":6}', NULL, 1, 1775638556000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000010-run0-4000-8000-run000000010', 'run-continuous-level-10', 'Continuous Run — 35 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Start at a conservative pace (HR 120–125) for the first 5 minutes, then let it settle to your Zone 2 band (125–135 bpm).","For 35 minutes of Zone 2, pacing strategy matters: start easy so the second half stays aerobic.","Target pace: 6:30–8:30 min/km (7–9 km/h) on flat terrain. Hills: reduce pace to keep HR below 135.","Last 5 minutes: check your form — relaxed shoulders, quiet foot strike, natural arm swing. This is your aerobic signature at work."],"cues":["💡 HR 130 bpm is your target. Under 125 = too easy, over 135 = too hard","💡 Treadmill reference: 8 km/h at 1% incline. Adjust by ±0.5 km/h to hit your HR zone","💡 At 35+ minutes, fuelling strategy begins to matter: hydrate before long Zone 2 runs","💡 Zone 2 at this duration significantly improves fat oxidation and running economy"]}', NULL, '{"supports":["time"],"base_duration_sec":2100,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000011-run0-4000-8000-run000000011', 'run-continuous-level-11', 'Continuous Run — 40 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Warm up at very easy pace (HR below 120) for 5 minutes, then settle into Zone 2 (HR 125–135).","40 minutes of Zone 2 — pace target 6:30–8:30 min/km (7–9 km/h) on flat. Use HR as your only real guide.","Mid-run check (20 min): still speaking easily? Good. Still feel like you have a lot left? Good. That is Zone 2.","Cool down: last 5 minutes naturally ease off as your pace holds but effort reduces — this is training adaptation beginning."],"cues":["💡 Zone 2 HR: 125–135 bpm throughout. Treadmill: start at 8 km/h at 1% incline","💡 At 40 minutes your body is primarily running on fat as fuel — efficient and sustainable","💡 This session is worth more than a 20-minute harder effort for aerobic development","💡 If HR drifts above 135 in the second half, reduce pace by 10 sec/km — not a failure, a correction"]}', NULL, '{"supports":["time"],"base_duration_sec":2400,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000012-run0-4000-8000-run000000012', 'run-continuous-level-12', 'Continuous Run — 45 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["45 minutes of Zone 2. Treat the first 10 minutes as a warm-up within the zone (HR 120–128), then settle at 130.","Pace: 6:30–8:30 min/km (7–9 km/h) on flat. On a treadmill: 7.5–8.5 km/h at 1% incline.","Strategy: split mentally into three 15-minute blocks. Each block: settle, hold, finish. Identical HR across all three.","The last 5 minutes should feel the same as minute 10 — that is your aerobic base working."],"cues":["💡 HR 130 bpm. Talk test still valid at 40+ minutes means you stayed aerobic — well done","💡 Treadmill: 8 km/h at 1% incline is the standard Zone 2 reference for most moderate-fitness runners","💡 45 minutes of Zone 2 per session is the training volume associated with significant VO2max gains","💡 Nutrition: for runs above 40 minutes, have a small carbohydrate snack 2 hours before"]}', NULL, '{"supports":["time"],"base_duration_sec":2700,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000013-run0-4000-8000-run000000013', 'run-continuous-level-13', 'Continuous Run — 50 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["50-minute Zone 2 run. Hydrate beforehand — at this duration, starting dehydrated affects HR and performance.","Settle at HR 125–135 bpm within the first 8 minutes. Pace: 6:30–8:30 min/km (7–9 km/h) on flat terrain.","Mid-point check (25 min): HR steady? Breathing easy? If HR has crept to 140+, you drifted — reduce pace 15 sec/km.","Finish strong in terms of form, not pace. Shoulders, stride, breathing — all relaxed."],"cues":["💡 50 minutes at HR 130 is a significant aerobic training dose — more effective than 25 minutes at HR 155","💡 Treadmill: 7.5–8.5 km/h at 1% incline. Adjust by ±0.3 km/h to hold your HR band","💡 Cardiac drift is normal: HR may rise 3–5 bpm over the session with pace unchanged","💡 Zone 2 pace will improve 20–30 sec/km over a 12-week training block at this volume"]}', NULL, '{"supports":["time"],"base_duration_sec":3000,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000014-run0-4000-8000-run000000014', 'run-continuous-level-14', 'Continuous Run — 55 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["55-minute Zone 2 run. Choose a route or treadmill setting you can sustain without interruption — continuous running delivers more aerobic stimulus than stop-start.","Target: HR 125–135 bpm throughout. Pace: 6:30–8:30 min/km (7–9 km/h). On treadmill: 8 km/h at 1% incline is the reference starting point.","At 30 minutes, assess: HR stable? Stride smooth? If effort feels the same as minute 10, your aerobic base is working.","Last 10 minutes: maintain form. Quiet feet, relaxed arms, upright posture. This is where the training adaptation is earned."],"cues":["💡 HR 130 is the sweet spot — enough stimulus to build base, low enough to recover fully in 24 hours","💡 A 55-minute Zone 2 run = more aerobic gain than two 25-minute moderate-effort runs","💡 Treadmill: 1% incline corrects for the lack of air resistance — never run flat on a treadmill","💡 You should finish this run feeling like you could do another 15 minutes. That is correct."]}', NULL, '{"supports":["time"],"base_duration_sec":3300,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000015-run0-4000-8000-run000000015', 'run-continuous-level-15', 'Continuous Run — 60 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["60-minute Zone 2 run — one full hour. Hydrate properly beforehand. Carry water if temperature is above 15°C.","Settle at HR 125–135 bpm within the first 8 minutes. Pace: 6:30–8:30 min/km (7–9 km/h). Treadmill: 8 km/h at 1% incline as your starting reference.","Divide into four 15-minute blocks. Block 1: settle in. Block 2: find your rhythm. Block 3: manage fatigue. Block 4: finish with intent.","At 45 minutes, your mental game matters as much as your physical fitness. Stay present — one kilometre at a time."],"cues":["💡 60 minutes at HR 130 is one of the most effective single aerobic training sessions available","💡 Cardiac drift: HR may rise 5 bpm in the final 20 minutes with pace unchanged — this is normal","💡 An hour of Zone 2 running significantly elevates VO2max over a training cycle","💡 Eat a small carbohydrate snack (banana, oats) 2 hours before runs of this duration"]}', NULL, '{"supports":["time"],"base_duration_sec":3600,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000016-run0-4000-8000-run000000016', 'run-continuous-level-16', 'Long Run — 75 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["75-minute Zone 2 run. This is a serious long run — plan your route, carry water, and eat a carbohydrate snack 2 hours before.","HR target: 125–135 bpm. Pace: 6:30–8:30 min/km. On treadmill: 8 km/h at 1% incline, adjusting by ±0.5 to hold your zone.","For runs above 60 minutes, managing HR drift matters: if HR rises above 135 after 45 minutes, reduce pace — do not push through.","Last 15 minutes: check your form actively. Fatigue affects posture first — shoulders drop, stride shortens. Correct it consciously."],"cues":["💡 HR 130 × 75 minutes = maximum polarised training stimulus without significant recovery debt","💡 Fat is your primary fuel at Zone 2. Glycogen stores last 90+ minutes at this intensity — no fuelling needed for most runners","💡 Treadmill at this duration: check the fan, keep a water bottle in reach, accept that it is mentally demanding","💡 After this run, 36 hours of easy activity maximises aerobic adaptation"]}', NULL, '{"supports":["time"],"base_duration_sec":4500,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000017-run0-4000-8000-run000000017', 'run-continuous-level-17', 'Long Run — 90 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["90-minute Zone 2 run. Fuel and hydrate before you start — at 90 minutes, even Zone 2 depletes glycogen stores in some runners.","Hold HR 125–135 bpm throughout. Pace: 6:30–8:30 min/km. After 60 minutes, pace may need to slow 10–15 sec/km to hold the same HR — this is correct, not failure.","Mental strategy: break into three 30-minute segments. Each has its own challenge: warmup, build, hold. The final 30 minutes is where endurance is built.","Last 10 minutes: active cool down within the run — same pace, conscious relaxation of effort."],"cues":["💡 Cardiac drift at 90 minutes can add 8–10 bpm to HR at the same pace — slow down, not push through","💡 If you have running gels or blocks, one at 60 minutes helps maintain Zone 2 without bonking","💡 90 minutes at Zone 2 is the backbone of distance runner training — this is what marathon pace is built on","💡 Recovery: full rest day tomorrow, or very light mobility only"]}', NULL, '{"supports":["time"],"base_duration_sec":5400,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000018-run0-4000-8000-run000000018', 'run-continuous-level-18', 'Long Run — 105 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["105-minute Zone 2 run. Mandatory preparation: hydrate the day before, eat a proper carbohydrate meal, carry water or plan a water stop.","HR 125–135 bpm. Pace: 6:30–8:30 min/km. Expect your sustainable pace to drop by 15–20 sec/km versus your shorter runs — this is normal at this duration.","First 20 minutes: resist the urge to run faster than HR 130. The last 40 minutes will thank you.","From 75 minutes onward: run on your aerobic system alone. HR steady, mind focused on form."],"cues":["💡 At 1 hour 45 minutes, this is genuine long-run territory. Your pace does not matter — time on feet at Zone 2 does.","💡 Fuel at 60 minutes and 90 minutes: 25–35g of fast carbohydrate (gel, banana, dates)","💡 After this run, active recovery for 48 hours — no HIIT, no strength. Let the aerobic adaptation consolidate.","💡 This is where your aerobic engine gets built. The discomfort is the signal."]}', NULL, '{"supports":["time"],"base_duration_sec":6300,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000019-run0-4000-8000-run000000019', 'run-continuous-level-19', 'Long Run — 120 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["120-minute Zone 2 run. Full preparation required: hydrate 24 hours before, eat carbohydrates the morning of, carry or plan for fluids.","HR 125–135 bpm throughout. Pace will naturally be 20–25 sec/km slower than your shorter Zone 2 runs by the final 30 minutes — hold the HR, not the pace.","First 30 minutes: disciplined patience. Your legs want to run faster. Resist — you are building an aerobic engine.","Final 30 minutes: these minutes are the most valuable of the entire session. Stay present, hold form, complete the run."],"cues":["💡 2 hours at Zone 2 is the signature long run of half-marathon preparation","💡 Fuelling strategy: 30–40g carbohydrate at 45, 90 minutes. Hydrate every 20 minutes.","💡 Your fat-burning efficiency improves most dramatically from runs above 90 minutes at Zone 2","💡 Post-run: protein + carbohydrates within 30 minutes, full rest day tomorrow"]}', NULL, '{"supports":["time"],"base_duration_sec":7200,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000020-run0-4000-8000-run000000020', 'run-continuous-level-20', 'Long Run — 150 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["150-minute Zone 2 run. This is a significant athletic undertaking — treat it as a training event, not just a run.","HR 125–133 bpm. Expect pace to drift significantly in the second half — this is correct. Let HR govern entirely.","Nutrition required: eat 30–40g carbohydrate every 45 minutes (gel, banana, bar). Hydrate every 20 minutes.","Last 30 minutes: fatigue is real. Focus entirely on form — quiet feet, upright posture, relaxed hands. The aerobic adaptation is happening right now."],"cues":["💡 2.5 hours at Zone 2 is approaching marathon long-run territory — few non-athletes attempt this. You are building something significant.","💡 Pace at 2+ hours: 7:00–9:00 min/km is normal even for trained runners. Let go of pace ego.","💡 Cardiac drift at this duration can add 10–12 bpm — reduce pace proactively, do not wait for it to force you","💡 Recovery: 48 hours easy activity minimum. Sleep is the most important training adaptation tool."]}', NULL, '{"supports":["time"],"base_duration_sec":9000,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000021-run0-4000-8000-run000000021', 'run-continuous-level-21', 'Long Run — 180 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["180-minute Zone 2 run — 3 hours. This is elite-range long run volume. Prepare as you would for a race: sleep, nutrition, hydration, gear.","HR 120–130 bpm. Pace expectations: 7:00–9:00 min/km. After 90 minutes, pace will likely be slower — this is correct and expected at this duration.","Nutrition: 30–40g carbohydrate every 40 minutes from the start. Hydrate every 20 minutes. Consider electrolytes (sodium) for runs above 2 hours.","This run is not about pace, speed, or distance. It is about 3 hours of continuous aerobic work at Zone 2. The adaptation from this single session is extraordinary."],"cues":["💡 3-hour Zone 2 runs are the foundation of marathon and ultra training. You are training your body to run on fat.","💡 At 2+ hours: fat oxidation is near-maximum. Your body is learning to spare glycogen — this takes weeks to express.","💡 HR will drift. At 2.5 hours, 128–133 bpm at a walk/jog is still Zone 2 work. Do not push harder.","💡 Recovery: full rest day tomorrow, protein-focused nutrition, 9+ hours sleep if possible."]}', NULL, '{"supports":["time"],"base_duration_sec":10800,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000007-run0-4000-8000-run000000007', 'run-continuous-level-7', 'Continuous Run — 20 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Set your pace so your heart rate settles at 130 bpm — this is Zone 2, your aerobic base zone.","Target pace: 6:30–8:30 min/km (7–9 km/h). On a treadmill, start at 7.5 km/h at 1% incline and adjust. Slower is better than faster — HR governs, not pace.","If your HR rises above 135 bpm, reduce pace by 5–10 sec/km and hold there. This is not failure — it is exactly correct Zone 2 training.","Last 5 minutes: notice how stable your breathing feels. This is your aerobic engine working at its optimal intensity."],"cues":["💡 Talk test: say a full sentence out loud. If you cannot, slow down — you have left Zone 2","💡 Zone 2 builds mitochondrial density and fat-burning efficiency. Most runners go too fast on easy days.","💡 HR 130 = roughly 65–70% of max HR. Adjust target by ±5 bpm based on your age and fitness","💡 Polarised rule: this session should feel almost too easy. Save the hard effort for HIIT days."]}', NULL, '{"supports":["time"],"base_duration_sec":1200,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000008-run0-4000-8000-run000000008', 'run-continuous-level-8', 'Continuous Run — 25 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Start at a pace where your heart rate settles at 130 bpm. For most runners this is 7–9 km/h (6:40–8:30 min/km).","Maintain this effort for the full 25 minutes. Ignore your pace — if HR climbs above 135 on a hill, shorten your stride and power-walk the top.","You should be able to hold a conversation throughout. If you cannot say 3–4 words without gasping, you are running too fast.","After the session: your easy pace will improve over weeks as your aerobic base builds."],"cues":["💡 Zone 2 HR target: 125–135 bpm throughout","💡 Treadmill: 7.5–9 km/h at 1% incline. Outdoor: let HR govern, ignore pace","💡 The aerobic engine runs on fat at this intensity — this is where your base is built","💡 Feeling slow is correct. Most runners spend too much time in the inefficient middle zone."]}', NULL, '{"supports":["time"],"base_duration_sec":1500,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('a1000009-run0-4000-8000-run000000009', 'run-continuous-level-9', 'Continuous Run — 30 min', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","outdoor","running","no_floor","run_continuous","zone2","loads_knee","loads_ankle"]', '["running_shoes"]', NULL, '{"steps":["Settle into Zone 2 within the first 5 minutes — HR 125–135 bpm, pace that allows easy conversation.","Hold this steady state for the full 30 minutes. Adjust pace by terrain: uphill = slower stride, downhill = let it flow naturally.","Target pace: 6:30–8:30 min/km (7–9 km/h) on flat terrain. On treadmill: 8 km/h at 1% incline is a good reference.","Mental check at 20 minutes: if your breathing has changed significantly since minute 5, you are drifting into Zone 3 — slow down."],"cues":["💡 Zone 2 HR: 125–135 bpm. If a hill pushes you to 140+, walk the top.","💡 30 minutes of Zone 2 is a complete aerobic stimulus — no need to go faster","💡 Your Zone 2 pace will improve significantly over 8–12 weeks of consistent easy running","💡 Easy days easy, hard days hard. This is the foundation of polarised training."]}', NULL, '{"supports":["time"],"base_duration_sec":1800,"custom_rest_sec":0,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('b2000002-warm-4000-8000-wrup00000002', 'run-warmup-calf-raises', 'Calf Raises', 'mobility', '["calves","soleus"]', NULL, '["cardio","low_impact","no_floor","outdoor","bodyweight","run_warmup","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Stand with feet hip-width apart, toes pointing forward. You can rest fingertips on a wall for balance.","Rise onto your toes as high as you comfortably can and hold for 1 second at the top.","Lower slowly and with control — aim for a 2-second descent. Repeat continuously for the full duration."],"cues":["💡 The slow lowering phase is where the calf strength is built — do not rush it","💡 Rise from the big toe side of your foot for better ankle stability when running"]}', NULL, '{"supports":["time"],"base_duration_sec":30,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('b2000003-warm-4000-8000-wrup00000003', 'run-warmup-high-knees-march', 'High Knees March', 'mobility', '["hip_flexors","quadriceps","calves"]', NULL, '["cardio","low_impact","no_floor","outdoor","bodyweight","run_warmup","loads_knee"]', '["none"]', NULL, '{"steps":["March in place at a steady rhythm, lifting each knee to hip height with each step.","Pump your arms in opposition — left arm forward with right knee up, right arm with left knee.","Keep your torso tall and your gaze forward. Breathe rhythmically with your movement."],"cues":["💡 This primes your hip flexors and gets your cardiovascular system online before the run","💡 Exaggerate the arm drive — your arms set the pace for your legs"]}', NULL, '{"supports":["time"],"base_duration_sec":30,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('b2000004-warm-4000-8000-wrup00000004', 'run-warmup-hip-circles', 'Hip Circles', 'mobility', '["glutes","hip_flexors","adductors"]', NULL, '["cardio","low_impact","no_floor","outdoor","bodyweight","run_warmup","loads_knee"]', '["none"]', NULL, '{"steps":["Stand with feet shoulder-width apart and place both hands on your hips.","Draw large, slow circles with your hips — 5 clockwise, then 5 counter-clockwise. Make each circle bigger than the last.","Keep your knees soft and your upper body as still as possible — the movement comes only from the hips and pelvis."],"cues":["💡 This opens the hip joint before impact loading — do not rush it","💡 Tightness or restriction in one direction tells you which side needs more mobility work"]}', NULL, '{"supports":["time"],"base_duration_sec":45,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('b2000001-warm-4000-8000-wrup00000001', 'run-warmup-leg-swings', 'Leg Swings', 'mobility', '["hip_flexors","hamstrings","glutes"]', NULL, '["cardio","low_impact","no_floor","outdoor","bodyweight","run_warmup","loads_knee"]', '["none"]', NULL, '{"steps":["Stand at arm''s length from a wall, resting one hand lightly on it for balance.","Swing your right leg forward and back in a controlled arc — 10 smooth repetitions, gradually increasing the range.","Switch legs and repeat. Keep your core lightly braced and your standing foot flat on the ground."],"cues":["💡 Let momentum do the work — this is a dynamic stretch, not a kick","💡 If your hip flexors feel tight, that is exactly what this is for — keep going"]}', NULL, '{"supports":["time"],"base_duration_sec":30,"fixed_sets":1}', NULL, 1, 1775659079000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000006-obke-4000-8000-hiit00000006', 'outdoor-bike-hiit', 'Road Bike — HIIT Intervals', 'cardio', '["quadriceps","hamstrings","glutes","calves","hip_flexors"]', NULL, '["cardio","low_impact","outdoor","no_floor","hiit","cycling"]', '["outdoor_bike"]', NULL, '{"steps":["Choose a route with clear sprint sections — flat straights or consistent climbs of 2–4 minutes. Warm up at easy pace for 10 minutes (HR below 125, 80 RPM).","Effort interval: sprint at 85–95% effort. Speed target on flat: 30–45 km/h. Power meter: 85–100% of FTP. Standing sprints on climbs, seated sprints on flat. HR target: 165–178 bpm.","Recovery: easy spin at 15–22 km/h, 70–80 RPM. Let HR drop below 130 before the next effort. Do not stop pedalling during recovery.","Repeat the effort/recovery pattern throughout the session. Final 10 minutes: easy cool-down spin."],"cues":["💡 Power meter targets: effort 85–100% FTP (e.g. 170–200W for a 200W FTP). Recovery 40–55% FTP.","💡 Cadence in sprints: flat sprints 90–110 RPM. Climbing efforts 75–90 RPM. Match cadence to terrain.","💡 Outdoor HIIT: natural terrain resistance — hills and headwinds give you variable, effective overload","💡 Use full warm-up before first effort. Outdoor conditions (cold, wind) mean muscles need longer preparation."]}', NULL, '{"supports":["time"],"base_duration_sec":2700}', NULL, 1, 1775661357000, 1775661357000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000005-obke-4000-8000-zone20000005', 'outdoor-bike-zone2', 'Road Bike — Zone 2 Ride', 'cardio', '["quadriceps","hamstrings","glutes","calves"]', NULL, '["cardio","low_impact","outdoor","no_floor","zone2","cycling"]', '["outdoor_bike"]', NULL, '{"steps":["Choose a flat-to-gently-rolling route. Settle into Zone 2 within the first 10 minutes: HR 125–135 bpm, cadence 80–90 RPM.","Speed target on flat terrain: 20–28 km/h. If you have a power meter, hold 50–65% of your FTP (Functional Threshold Power). Both are Zone 2 markers.","Climbs: shift down and maintain cadence (80–90 RPM) rather than grinding. If HR exceeds 138 bpm on climbs, accept slower speed — HR governs.","Descents: recover actively. Let HR drop back toward 120 bpm on long descents, then re-engage at Zone 2 effort on the flat."],"cues":["💡 Talk test at 25 km/h: if you cannot speak in phrases, you are above Zone 2 — ease off the power","💡 Cadence 80–90 RPM is more efficient than grinding at 60–70 RPM at the same wattage","💡 Power meter riders: Zone 2 = 55–75% FTP (e.g. if FTP is 200W, Zone 2 = 110–150W)","💡 Outdoor Zone 2: terrain variability is fine — manage HR to stay in zone across hills and flats"]}', NULL, '{"supports":["time"],"base_duration_sec":2700}', NULL, 1, 1775661357000, 1775661357000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000004-bike-4000-8000-hiit00000004', 'static-bike-hiit', 'Static Bike — HIIT Intervals', 'cardio', '["quadriceps","hamstrings","glutes","calves","hip_flexors"]', NULL, '["cardio","low_impact","indoor","no_floor","hiit","cycling"]', '["stationary_bike"]', NULL, '{"steps":["Warm up at 70–90W, 80 RPM for 5 minutes — HR should reach 110–120 before intervals.","Effort interval: increase resistance to target wattage. Beginners: 130–170W. Intermediate: 170–230W. Advanced: 230–300W+. Cadence 90–110 RPM. This should feel like 8–9 out of 10 effort — HR 165–178 bpm.","Recovery interval: drop to 60–90W at 70–80 RPM. Let HR fall to 120–130 bpm before the next effort. Do not stop pedalling.","Repeat effort/recovery. Cool down 5 minutes at 60–80W, 75 RPM."],"cues":["💡 Watt progression: beginners 130–170W effort / 60–80W recovery. Intermediate 170–230W / 70–90W. Advanced 230–300W+ / 80–100W.","💡 Cadence during efforts: 90–110 RPM. High cadence trains your cardiovascular system; high resistance trains your legs. Do both.","💡 Static bike HIIT is among the safest high-intensity cardio options — zero impact, consistent resistance.","💡 HR target during effort: 165–178 bpm. If you cannot reach 160 bpm, increase resistance by 2–3 levels."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', NULL, 1, 1775661357000, 1775661357000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000003-bike-4000-8000-zone20000003', 'static-bike-zone2', 'Static Bike — Zone 2', 'cardio', '["quadriceps","hamstrings","glutes","calves"]', NULL, '["cardio","low_impact","indoor","no_floor","zone2","cycling"]', '["stationary_bike"]', NULL, '{"steps":["Set resistance so you spin smoothly at 80–90 RPM without bouncing in the saddle. Start conservative — adjust resistance up if HR stays below 120 after 5 minutes.","Target wattage: 80–100W for beginners, 100–150W for intermediate, 150–180W for trained cyclists. Let HR be your guide: settle at 125–135 bpm.","Hold this steady state for the full session. RPM should stay in the 80–90 range — smooth, controlled pedal circles, not choppy punches.","Check HR at 10, 20, 30 minutes. It should remain within 5 bpm of your Zone 2 target. Adjust resistance by 1–2 levels if needed."],"cues":["💡 RPM 80–90 is Zone 2 cadence — spinning smoothly at moderate resistance trains aerobic efficiency","💡 Watt targets: beginners 80–100W, intermediate 100–140W, advanced 140–180W. These align with HR 125–135 for most people.","💡 Talk test: you should be able to speak full sentences throughout. The bike should feel like light work.","💡 Zone 2 cycling is low-impact but high-stimulus. 45 minutes delivers aerobic adaptation equivalent to 35 minutes of Zone 2 running."]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', NULL, 1, 1775661357000, 1775661357000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000002-tdml-4000-8000-hiit00000002', 'treadmill-hiit', 'Treadmill — HIIT Intervals', 'cardio', '["quadriceps","calves","hamstrings","glutes","hip_flexors"]', NULL, '["cardio","high_impact","indoor","running","no_floor","hiit","treadmill","loads_knee","loads_ankle"]', '["treadmill"]', NULL, '{"steps":["Set incline to 1%. Warm up at 6 km/h for 3 minutes — HR should reach 110–120 bpm before intervals begin.","Effort interval: increase to 11–14 km/h. Target effort: 85–90% max, HR 160–175 bpm. Beginners start at 10–11 km/h — increase over sessions.","Recovery interval: reduce to 5.5–6.5 km/h (brisk walk). Let HR drop below 130 bpm before the next effort. Full recovery is what makes HIIT work.","Repeat effort/recovery pattern. Final 3 minutes: cool down at 5.5 km/h. Never stop abruptly after hard intervals."],"cues":["💡 Speed targets: effort 11–14 km/h (4:17–5:27 min/km equivalent). Recovery 5.5–6 km/h walking pace","💡 HR during effort: 160–175 bpm. If you cannot reach 158 bpm, increase speed by 0.5 km/h","💡 Pre-programme your effort and recovery speeds before starting — transitions must be fast (under 10 seconds)","💡 HIIT treadmill: 2:1 recovery ratio (e.g. 1 min effort / 2 min walk) is standard for beginners"]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', NULL, 1, 1775661357000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('c3000001-tdml-4000-8000-zone20000001', 'treadmill-zone2', 'Treadmill — Zone 2 Run', 'cardio', '["quadriceps","calves","hamstrings","glutes"]', NULL, '["cardio","high_impact","indoor","running","no_floor","zone2","treadmill","loads_knee","loads_ankle"]', '["treadmill"]', NULL, '{"steps":["Set treadmill to 1% incline — this compensates for the absence of air resistance and more closely matches outdoor running effort.","Start at 7.5 km/h and let your HR settle over 3–5 minutes. Target zone: 125–135 bpm. Adjust speed in 0.3 km/h increments until you find your personal Zone 2 speed.","Hold your Zone 2 speed for the full session. Speed guide: beginners 7–8 km/h, intermediate 8–9.5 km/h, trained 9.5–11 km/h. HR governs — not pace.","If HR rises above 135 at any point (especially on long sessions), reduce speed by 0.3 km/h and hold. Cardiac drift over 30+ minutes is normal."],"cues":["💡 Talk test: say 5 words comfortably without gasping. If you cannot, you are above Zone 2 — reduce speed.","💡 Treadmill Zone 2 reference: 8 km/h at 1% incline suits most recreational runners (HR ~125–135)","💡 Never run flat on a treadmill for Zone 2 — 1% incline is not optional for accurate training","💡 Zone 2 pace will improve 15–25 sec/km over 8 weeks of consistent training without increasing perceived effort"]}', NULL, '{"supports":["time"],"base_duration_sec":1800}', NULL, 1, 1775661357000, 1744900000000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('df61815885120e083aa9f95ff54c6195', 'cooldown-walk', 'Cool-down Walk', 'cardio', NULL, NULL, '["cardio","low_impact","outdoor","no_floor","recovery","session_phase","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Walk at a comfortable, relaxed pace — do not stop abruptly after an intensive effort","Let your heart rate come down naturally over 5 minutes","Focus on slow, deep breathing: inhale through the nose, exhale through the mouth","Shake out your legs gently and note how they feel — useful data for your next session"],"cues":["💡 Stopping abruptly after maximal effort can cause dizziness — keep moving","Your heart rate should drop below 120 bpm within 2–3 minutes at walking pace"]}', NULL, '{"supports":["time"],"base_duration_sec":300,"fixed_sets":1}', NULL, 1, 1777114247000, 1777114247000);
INSERT OR IGNORE INTO exercises (id, slug, name, category, primary_muscles_json, secondary_muscles_json, tags_json, equipment_required_json, equipment_advised_json, instructions_json, media_json, metrics_json, alternatives_json, is_active, created_at_ms, updated_at_ms) VALUES
  ('46502d1ff3109bf8b8a1311886ddf3d2', 'easy-jog-warmup', 'Easy Jog Warm-up', 'cardio', NULL, NULL, '["cardio","low_impact","outdoor","no_floor","zone1","session_phase","loads_knee","loads_ankle"]', '["none"]', NULL, '{"steps":["Jog at a very easy, conversational pace — Zone 1 only (you could hold a full conversation)","Keep your breathing relaxed and posture tall, eyes looking ahead","This is preparation, not training — slow to a walk immediately if you feel breathless","After 7 minutes you should feel warm and loose, not winded"],"cues":["💡 Zone 1 means you can speak full sentences without effort — if you cannot, slow down","Use this time to mentally rehearse your pacing strategy for the effort ahead"]}', NULL, '{"supports":["time"],"base_duration_sec":420,"fixed_sets":1}', NULL, 1, 1777114247000, 1777114247000);

